INSERT INTO `tbl_news` (`news_id`, `news_title`, `news_content`, `news_content_short`, `news_date`, `published_at`, `photo`, `banner`, `category_id`, `author_id`, `comment`, `meta_title`, `meta_keyword`, `meta_description`, `lang_id`, `stitle`, `title`, `img_alt`, `domain_id`, `encode_title`, `type`) VALUES
(1, 'India Launches Unified Pension Scheme for 2.3 Million Central Government Employees', '<p>The Government of India has officially rolled out the Unified Pension Scheme, replacing the existing National Pension System for central government employees. The new scheme guarantees 50% of the average basic pay drawn over the last 12 months of service as a monthly pension after a minimum of 25 years of service. For employees with 10 to 25 years of service, a proportionate assured pension will apply. The Finance Ministry confirmed that approximately 2.3 million central employees are covered immediately, with state governments invited to adopt the scheme voluntarily. Economists noted that the assured pension model restores a degree of retirement certainty that was lost under the market-linked NPS and is likely to ease industrial unrest among government workers. Contributions from the government side have been raised to 18.5% of basic pay to fund the guaranteed element.</p>', 'India launches the Unified Pension Scheme guaranteeing 50% of last salary for central employees after 25 years of service.', '01 April 2025', '2025-04-01 09:00:00', 'news-india-001.webp', 'news-banner-india-001.webp', 1, 1, 'On', 'India Unified Pension Scheme Central Government 2025', 'unified pension scheme, UPS India, central government pension, NPS replacement', 'India rolls out the Unified Pension Scheme for 2.3 million central employees, guaranteeing 50% of last pay as monthly pension.', 5, 'India Unified Pension Scheme 2025', 'India Launches Unified Pension Scheme for 2.3 Million Central Government Employees', 'India unified pension scheme central government 2025', 1, 'india-unified-pension-scheme-central-government', 'india'),
(2, 'Kerala Becomes First Indian State to Achieve 100% Broadband Connectivity', '<p>Kerala has become the first state in India to achieve 100% broadband connectivity across all 941 gram panchayats, completing a seven-year effort under the Kerala Fibre Optic Network project. The state government confirmed that every village-level administrative unit now has access to high-speed internet with a minimum guaranteed speed of 100 Mbps. The project, executed through public sector utility Kerala State IT Infrastructure Limited, laid over 30,000 kilometres of optical fibre reaching deep into forest-fringe communities and islands. Digital literacy camps running alongside the rollout have enrolled over 1.2 million residents in basic internet skills programmes. The Union Ministry of Electronics and IT has cited Kerala as a model for the national BharatNet Phase 3 implementation across other states.</p>', 'Kerala becomes the first Indian state to connect all 941 gram panchayats with 100 Mbps broadband under K-FON.', '12 April 2025', '2025-04-12 10:00:00', 'news-india-002.webp', 'news-banner-india-002.webp', 1, 1, 'On', 'Kerala 100 Percent Broadband K-FON India First', 'Kerala broadband, K-FON, 100 percent connectivity India, BharatNet', 'Kerala achieves 100% broadband connectivity across all gram panchayats, becoming a national model for digital inclusion.', 5, 'Kerala 100 Percent Broadband First India', 'Kerala Becomes First Indian State to Achieve 100% Broadband Connectivity', 'Kerala K-FON 100 percent broadband gram panchayat', 1, 'kerala-first-indian-state-100-percent-broadband', 'india'),
(3, 'India Ratifies Global Plastics Treaty, Pledges 70% Cut in Single-Use Plastic by 2030', '<p>India signed and ratified the UN Global Plastics Treaty in Geneva, committing to a 70% reduction in single-use plastic production and consumption by 2030. Environment Minister Bhupender Yadav called the treaty a landmark step and confirmed that India will phase out 19 additional categories of single-use plastics beyond those already banned. The Ministry of Environment has launched a Plastic Credit Mechanism under which industries that recover and recycle plastic waste earn tradeable credits. Extended producer responsibility norms will be tightened, making packaging companies financially liable for post-consumer waste collected nationally. India also pledged $200 million to support developing nations in South Asia and Africa to build plastic waste management infrastructure as part of its commitment under the treaty.</p>', 'India ratifies the UN Global Plastics Treaty, pledging a 70% cut in single-use plastics by 2030 and $200M for developing nations.', '22 May 2025', '2025-05-22 11:00:00', 'news-india-003.webp', 'news-banner-india-003.webp', 1, 1, 'On', 'India Global Plastics Treaty Single Use Plastic 2030', 'India plastics treaty, single use plastic ban India, UN plastics agreement', 'India ratifies the UN Global Plastics Treaty with a 70% single-use plastic reduction target and EPR norms.', 5, 'India Global Plastics Treaty 2025', 'India Ratifies Global Plastics Treaty, Pledges 70% Cut in Single-Use Plastic by 2030', 'India UN plastics treaty single use plastic 2030', 1, 'india-ratifies-global-plastics-treaty-2030', 'india'),
(4, 'Supreme Court Orders Mandatory Live-Streaming of All High Court Proceedings', '<p>The Supreme Court of India issued a landmark directive ordering all 25 High Courts across the country to begin live-streaming their proceedings within six months, citing the fundamental right of citizens to access justice as a public good. The bench, led by Chief Justice Sanjiv Khanna, noted that live-streaming of Supreme Court hearings had significantly improved transparency and public trust and that the same principle must cascade to High Courts. The order provides an opt-out mechanism for proceedings involving sensitive matters such as child custody, sexual offences, and national security. The National Informatics Centre has been directed to build a unified live-streaming portal accessible via the eCourts mobile application. Legal observers described the ruling as the most significant judicial transparency reform since the Right to Information Act.</p>', 'Supreme Court orders all 25 High Courts to live-stream proceedings within six months, citing citizens right to access justice.', '08 June 2025', '2025-06-08 10:30:00', 'news-india-004.webp', 'news-banner-india-004.webp', 1, 1, 'On', 'Supreme Court Live Streaming High Courts India 2025', 'Supreme Court live streaming, High Court proceedings India, judicial transparency', 'Supreme Court orders mandatory live-streaming of all High Court proceedings within six months.', 5, 'Supreme Court High Court Live Streaming', 'Supreme Court Orders Mandatory Live-Streaming of All High Court Proceedings', 'Supreme Court India High Court live streaming 2025', 1, 'supreme-court-live-streaming-high-courts-india', 'india'),
(5, 'India Completes Its Longest River-Linking Canal Connecting Ken and Betwa', '<p>India has completed the first phase of the Ken-Betwa River Linking Project, inaugurating a 221-kilometre canal that will transfer surplus water from the Ken river in Madhya Pradesh to the drought-prone Betwa basin. The project, the first of 30 planned inter-river linkages under India national river-linking programme, is expected to irrigate 1.08 million hectares and provide drinking water to 6.2 million people in the Bundelkhand region, one of India most water-stressed zones. The Daudhan Dam, the key storage infrastructure of the project, reached its designed height of 73 metres after six years of construction. Critics have raised concerns about the submergence of over 9,000 hectares of Panna Tiger Reserve forest, though wildlife corridors have been constructed as mitigation. The Union Water Minister called completion a transformational moment for Central India agriculture.</p>', 'India completes the Ken-Betwa river link canal, irrigating 1.08 million hectares in drought-prone Bundelkhand region.', '15 July 2025', '2025-07-15 08:00:00', 'news-india-005.webp', 'news-banner-india-005.webp', 1, 1, 'On', 'Ken Betwa River Linking Project Bundelkhand India', 'Ken Betwa river linking, Bundelkhand water, India river link canal', 'India completes the Ken-Betwa river linking canal, providing irrigation and drinking water to 6.2 million people.', 5, 'Ken Betwa River Link India Completed', 'India Completes Its Longest River-Linking Canal Connecting Ken and Betwa', 'Ken Betwa river linking project India completed', 1, 'india-ken-betwa-river-linking-canal-completed', 'india'),
(6, 'India Wins Permanent Seat Observers Status at Arctic Council', '<p>India has been granted enhanced Observer status at the Arctic Council, giving it a permanent advisory seat and access to all working group meetings of the body that governs the world most rapidly changing geography. The Ministry of External Affairs described the development as a milestone in India Arctic policy, which has operated under the National Centre for Polar and Ocean Research since 2007. India Himadri research station at Ny-Aalesund in Norway will serve as the operational hub for expanded Arctic engagement. Officials noted that melting Arctic ice is opening new shipping routes that could cut transit time between India and Europe by up to 40%, with the Northern Sea Route becoming commercially viable by the early 2030s. India pledged to contribute climate monitoring data and cryosphere research findings to the Council shared knowledge base.</p>', 'India gains permanent Observer status at the Arctic Council, unlocking access to governance meetings and new polar research opportunities.', '28 July 2025', '2025-07-28 09:00:00', 'news-india-006.webp', 'news-banner-india-006.webp', 1, 1, 'On', 'India Arctic Council Observer Status 2025', 'India Arctic Council, Arctic policy India, Himadri station', 'India granted permanent Observer status at the Arctic Council, expanding its polar research and maritime interests.', 5, 'India Arctic Council Observer 2025', 'India Wins Permanent Observer Status at Arctic Council', 'India Arctic Council observer status 2025', 1, 'india-permanent-observer-arctic-council', 'india'),
(7, 'Cabinet Approves National Quantum Mission with Rs 6,003 Crore Outlay', '<p>The Union Cabinet has approved the National Quantum Mission with a total outlay of Rs 6,003 crore over eight years, making India only the seventh country in the world to launch a dedicated national quantum technology programme. The mission targets the development of intermediate-scale quantum computers with 50 to 1,000 physical qubits by 2031, alongside quantum communication networks, quantum sensing devices, and quantum material research. Four Thematic Hubs will be established at premier institutions including IISc Bengaluru, IIT Bombay, IIT Delhi, and TIFR Mumbai. The Department of Science and Technology has already shortlisted 14 startups working on quantum hardware and software that will receive initial grants. Officials said India aims to be among the global top three nations in quantum technology by 2035.</p>', 'Cabinet approves Rs 6,003 crore National Quantum Mission to build 50-1000 qubit computers and quantum networks by 2031.', '10 August 2025', '2025-08-10 10:00:00', 'news-india-007.webp', 'news-banner-india-007.webp', 1, 1, 'On', 'India National Quantum Mission Cabinet 2025', 'National Quantum Mission India, quantum computing India, NQM 6003 crore', 'Cabinet approves Rs 6,003 crore National Quantum Mission targeting quantum computers and communication by 2031.', 5, 'India National Quantum Mission 2025', 'Cabinet Approves National Quantum Mission with Rs 6,003 Crore Outlay', 'India National Quantum Mission cabinet approval 2025', 1, 'india-national-quantum-mission-6003-crore', 'india'),
(8, 'India Launches One Nation One Election Commission Report Fuels Debate', '<p>The High-Level Committee on Simultaneous Elections, chaired by former President Ram Nath Kovind, submitted its final report to the President of India, formally recommending that Lok Sabha and all state assembly elections be held simultaneously starting from 2029. The report proposes a two-phase model in which the Lok Sabha poll and a majority of state elections occur together in the first phase, with elections to remaining states and local bodies held within 100 days. Implementing the plan would require constitutional amendments to at least five articles and ratification by a majority of states. Opposition parties have strongly objected, arguing simultaneous elections would concentrate political power and disadvantage regional parties. The Election Commission has been asked to submit a technical feasibility report within three months.</p>', 'The Kovind Committee recommends simultaneous Lok Sabha and state elections from 2029 in a two-phase constitutional reform plan.', '22 August 2025', '2025-08-22 11:00:00', 'news-india-008.webp', 'news-banner-india-008.webp', 1, 1, 'On', 'One Nation One Election India Report 2025', 'one nation one election, simultaneous elections India, Kovind committee', 'Kovind Committee recommends simultaneous elections from 2029, requiring five constitutional amendments and state ratification.', 5, 'One Nation One Election Report India', 'India Launches One Nation One Election Commission Report Fuels Debate', 'India one nation one election Kovind report 2025', 1, 'india-one-nation-one-election-kovind-report', 'india'),
(9, 'Bengaluru Metro Phase 3 Inaugurated, Network Now Longest in India', '<p>Prime Minister Narendra Modi inaugurated Phase 3 of the Namma Metro in Bengaluru, adding 44.65 kilometres across three new corridors and pushing the city metro network to a total of 220 kilometres — overtaking Delhi to become the longest metro rail network in India. The new Phase 3 lines connect the outer ring road tech corridors of Sarjapur and Whitefield to the airport via an underground section beneath MG Road. Daily ridership projections for the expanded network stand at 1.5 million trips, which Bangalore Metro Rail Corporation says will remove approximately 400,000 private vehicles from the city roads daily. A real-time multimodal app integrating metro, BMTC bus, and auto-rickshaw booking was also launched alongside the inauguration. Bengaluru now has India highest metro ridership per kilometre of network.</p>', 'Bengaluru Metro Phase 3 opens, making Namma Metro at 220 km the longest metro network in India, surpassing Delhi.', '15 September 2025', '2025-09-15 09:00:00', 'news-india-009.webp', 'news-banner-india-009.webp', 1, 1, 'On', 'Bengaluru Metro Phase 3 Longest India 2025', 'Bengaluru metro phase 3, Namma Metro, longest metro India, BMRCL', 'Bengaluru Metro Phase 3 inaugurated, making it India longest metro at 220 km, overtaking Delhi.', 5, 'Bengaluru Metro Phase 3 Longest India', 'Bengaluru Metro Phase 3 Inaugurated, Network Now Longest in India', 'Bengaluru Metro Phase 3 India longest metro 2025', 1, 'bengaluru-metro-phase-3-longest-india', 'india'),
(10, 'India Hosts First Global South Summit in New Delhi', '<p>New Delhi hosted the inaugural Global South Summit, convened by India to establish a permanent multilateral forum for developing and emerging economies outside the G7 and G20 frameworks. Representatives from 126 countries attended, making it the largest gathering of Global South nations in diplomatic history. Prime Minister Modi unveiled a five-point Global South Charter covering debt restructuring, climate finance fairness, WTO reform, technology transfer, and UN Security Council expansion. The summit produced the Delhi Declaration, which calls for a 0.5% global wealth tax on billionaire assets to fund a dedicated Global South Development Fund. India announced it would host the summit annually and contribute Rs 1,000 crore to seed the Development Fund in its inaugural year.</p>', 'India hosts the inaugural Global South Summit in New Delhi, uniting 126 nations and launching the Delhi Declaration on development finance.', '02 October 2025', '2025-10-02 10:00:00', 'news-india-010.webp', 'news-banner-india-010.webp', 1, 1, 'On', 'India Global South Summit Delhi 2025', 'Global South Summit, India diplomacy, Delhi Declaration, developing nations', 'India hosts the inaugural Global South Summit, uniting 126 countries with the Delhi Declaration on debt and climate finance.', 5, 'India Global South Summit 2025', 'India Hosts First Global South Summit in New Delhi', 'India Global South Summit Delhi Declaration 2025', 1, 'india-global-south-summit-new-delhi-2025', 'india'),
(11, 'India Digital Rupee Daily Transactions Cross One Million for First Time', '<p>The Reserve Bank of India announced that daily transactions on the e-Rupee Central Bank Digital Currency platform crossed one million for the first time in a single day, marking a significant inflection point in the digital currency rollout that began in pilot form in December 2022. The CBDC is currently available through 13 banks via their mobile banking apps and supports both retail and wholesale transaction modes. The RBI attributed the surge to the integration of e-Rupee into the ONDC open commerce network, which allows digital rupee payments for online purchases across 50,000 merchants. Governor Sanjay Malhotra said the milestone validates India approach of a phased, interoperable CBDC rollout without disrupting the existing UPI ecosystem. International central banks from 14 countries have requested technical briefings from the RBI on the architecture.</p>', 'India e-Rupee CBDC crosses one million daily transactions as integration with ONDC drives adoption across 50,000 merchants.', '20 October 2025', '2025-10-20 08:30:00', 'news-india-011.webp', 'news-banner-india-011.webp', 1, 1, 'On', 'India Digital Rupee CBDC One Million Transactions 2025', 'digital rupee, e-Rupee CBDC, India CBDC, RBI digital currency', 'India e-Rupee CBDC crosses one million daily transactions, driven by ONDC integration and 13-bank rollout.', 5, 'India Digital Rupee One Million Transactions', 'India Digital Rupee Daily Transactions Cross One Million for First Time', 'India e-Rupee CBDC one million daily transactions 2025', 1, 'india-digital-rupee-one-million-transactions', 'india'),
(12, 'Maharashtra Launches World Largest Rooftop Solar Programme', '<p>The Maharashtra government has launched the Mukhyamantri Saur Krishi Vahini Yojana Phase 2, the world largest state-level rooftop solar programme, targeting installation of 7 gigawatts of rooftop solar capacity across 1.4 million households and 80,000 commercial establishments over three years. The scheme provides zero-cost loans for residential installations repayable over 15 years through electricity bill savings, making upfront cost a non-barrier for low-income families. Rooftop solar installations under the scheme will feed excess power into the grid at a guaranteed rate of Rs 3.50 per unit, creating passive income for households. Maharashtra Energy Development Agency has empanelled 1,200 certified solar installers across all 36 districts. Officials project the programme will reduce Maharashtra annual carbon emissions by 12 million tonnes and create 85,000 green energy jobs.</p>', 'Maharashtra launches the world largest rooftop solar scheme targeting 7 GW across 1.4 million homes with zero-cost loans.', '08 November 2025', '2025-11-08 09:00:00', 'news-india-012.webp', 'news-banner-india-012.webp', 1, 1, 'On', 'Maharashtra Rooftop Solar World Largest Programme 2025', 'Maharashtra rooftop solar, MSEDCL solar, India solar energy, Saur Krishi Vahini', 'Maharashtra launches world largest rooftop solar scheme targeting 7 GW, zero-cost loans, and 85,000 green jobs.', 5, 'Maharashtra Rooftop Solar World Largest', 'Maharashtra Launches World Largest Rooftop Solar Programme', 'Maharashtra rooftop solar largest world 2025', 1, 'maharashtra-rooftop-solar-world-largest-programme', 'india'),
(13, 'India Signs Defence Partnership with France for 26 Rafale Marine Jets', '<p>India and France concluded a government-to-government deal for the procurement of 26 Rafale Marine fighter jets for the Indian Navy, strengthening a bilateral defence partnership that has become one of India most strategically significant. The jets, manufactured by Dassault Aviation, will be deployed aboard the INS Vikrant aircraft carrier and a second carrier currently under construction at Cochin Shipyard. The deal, valued at approximately Rs 63,000 crore, includes Transfer of Technology provisions enabling Hindustan Aeronautics Limited to assemble a portion of the aircraft in India. France also agreed to share classified radar and electronic warfare technologies as part of the defence technology partnership framework. The Defence Acquisition Council has cleared the long-term maintenance agreement, which will be handled jointly by HAL and Dassault teams.</p>', 'India finalises a Rs 63,000 crore deal for 26 Rafale Marine jets for the Navy under a government-to-government France agreement.', '25 November 2025', '2025-11-25 11:00:00', 'news-india-013.webp', 'news-banner-india-013.webp', 1, 1, 'On', 'India Rafale Marine France Navy Deal 2025', 'Rafale Marine India, India France defence, INS Vikrant jets, HAL Rafale', 'India signs Rs 63,000 crore deal with France for 26 Rafale Marine jets for the Navy with ToT provisions.', 5, 'India Rafale Marine France Deal 2025', 'India Signs Defence Partnership with France for 26 Rafale Marine Jets', 'India Rafale Marine France defence deal 2025', 1, 'india-rafale-marine-france-defence-deal', 'india'),
(14, 'India Decriminalises Minor Traffic Violations in Motor Vehicles Amendment', '<p>Parliament has passed the Motor Vehicles Amendment Act 2025, decriminalising 34 minor traffic violations that previously carried imprisonment clauses, replacing custodial penalties with tiered monetary fines collected digitally via the VAHAN platform. The reform is intended to reduce the discretionary power of traffic police and curb corruption at enforcement checkpoints. Serious violations including drunk driving, racing, and overloading will continue to attract criminal liability. The Act also mandates that all commercial vehicles above 7.5 tonnes must be fitted with Advanced Driver Assistance Systems by 2027. Road Transport Minister Nitin Gadkari said the reform aligns India traffic law with international best practices and will be supported by 150,000 new AI-powered CCTV intersections to be installed across National Highways by 2026.</p>', 'India decriminalises 34 minor traffic violations under the Motor Vehicles Amendment Act 2025, replacing jail with digital fines.', '10 December 2025', '2025-12-10 09:00:00', 'news-india-014.webp', 'news-banner-india-014.webp', 1, 1, 'On', 'India Motor Vehicles Amendment Minor Traffic Violations 2025', 'Motor Vehicles Act amendment, traffic violation decriminalise India, VAHAN fine', 'India decriminalises 34 minor traffic violations under Motor Vehicles Amendment Act 2025 with digital fines.', 5, 'India Motor Vehicles Amendment 2025', 'India Decriminalises Minor Traffic Violations in Motor Vehicles Amendment', 'India Motor Vehicles Amendment traffic decriminalise 2025', 1, 'india-motor-vehicles-amendment-traffic-decriminalise', 'india'),
(15, 'India Opens World Largest Renewable Energy Park in Rann of Kutch', '<p>Prime Minister Narendra Modi inaugurated the Khavda Renewable Energy Park in Gujarat Rann of Kutch region, the world largest hybrid renewable energy facility spanning 72,600 hectares — roughly the size of Singapore. The park, developed by Adani Green Energy, combines 26 gigawatts of solar photovoltaic capacity with 8 gigawatts of wind power, making it the single largest clean energy installation on Earth. High-voltage direct current transmission lines carry power from the park to consumption centres across eight states. The project displaced no agricultural land or population as it occupies barren salt desert terrain. Gujarat Chief Minister stated that Khavda alone will supply power to 16 million homes and reduce India annual carbon dioxide emissions by 58 million tonnes once fully operational in 2026.</p>', 'India opens the Khavda Renewable Energy Park in Gujarat, the world largest hybrid clean energy facility at 34 GW total capacity.', '22 December 2025', '2025-12-22 10:00:00', 'news-india-015.webp', 'news-banner-india-015.webp', 1, 1, 'On', 'Khavda Renewable Energy Park World Largest Gujarat India', 'Khavda energy park, world largest solar wind India, Adani Green, Rann of Kutch energy', 'India opens the Khavda Renewable Energy Park, the world largest hybrid clean energy facility at 34 GW in Gujarat.', 5, 'Khavda World Largest Renewable Park India', 'India Opens World Largest Renewable Energy Park in Rann of Kutch', 'Khavda renewable energy park world largest Gujarat 2025', 1, 'india-khavda-renewable-energy-park-worlds-largest', 'india'),
(16, 'ISRO Successfully Tests Gaganyaan Crew Escape System at Full Scale', '<p>The Indian Space Research Organisation conducted a full-scale integrated test of the Crew Escape System for the Gaganyaan crewed spacecraft at the Satish Dhawan Space Centre, validating the abort system that will protect astronauts in the event of a launch failure. The test fired a solid rocket motor that carried a fully loaded crew module from zero altitude to approximately 2.7 kilometres in 16.5 seconds before safe parachute-assisted splashdown in the Bay of Bengal. All seven parachutes deployed as planned and the module was recovered undamaged within 35 minutes. ISRO Chairman V. Narayanan described the test as a critical milestone clearing the path for the uncrewed Gaganyaan orbital flight scheduled for late 2026. India first crewed orbital mission, carrying three Indian Air Force astronauts, is targeted for 2027.</p>', 'ISRO tests Gaganyaan full-scale crew escape system successfully, clearing the path for an uncrewed orbital flight in late 2026.', '14 January 2026', '2026-01-14 07:00:00', 'news-india-016.webp', 'news-banner-india-016.webp', 1, 1, 'On', 'ISRO Gaganyaan Crew Escape System Test 2026', 'Gaganyaan crew escape, ISRO crewed mission, India astronaut, Gaganyaan test', 'ISRO successfully tests Gaganyaan full-scale crew escape system, clearing the path to India first crewed space mission.', 5, 'ISRO Gaganyaan Crew Escape Test 2026', 'ISRO Successfully Tests Gaganyaan Crew Escape System at Full Scale', 'ISRO Gaganyaan crew escape system test 2026', 1, 'isro-gaganyaan-crew-escape-system-test-2026', 'india'),
(17, 'India Passes Data Protection Act with Stringent Consent and Localisation Rules', '<p>India Data Protection Act 2025 received Presidential assent and came into force, establishing a comprehensive legal framework governing how personal data of Indian citizens is collected, processed, and stored. The Act mandates explicit consent for data collection, grants citizens the right to erasure, portability, and grievance redressal, and requires significant data fiduciaries to appoint a Data Protection Officer. Cross-border data transfers are permitted only to countries cleared by a Data Protection Board, ruling out transfers to nations deemed inadequate in protection standards. Critical personal data — defined as data related to health, finance, biometrics, and children — must be stored exclusively on servers within India. Heavy penalties of up to Rs 250 crore per violation can be levied. Industry groups acknowledged the framework provides long-awaited legal clarity, though several raised concerns about localisation compliance costs.</p>', 'India Data Protection Act 2025 comes into force with consent mandates, erasure rights, and Rs 250 crore penalties for violations.', '01 February 2026', '2026-02-01 09:00:00', 'news-india-017.webp', 'news-banner-india-017.webp', 1, 1, 'On', 'India Data Protection Act 2025 Privacy Law', 'India data protection act, DPDP Act 2025, data privacy India, DPB India', 'India Data Protection Act 2025 enforced with consent rules, data localisation, and Rs 250 crore violation penalties.', 5, 'India Data Protection Act 2025 Enforced', 'India Passes Data Protection Act with Stringent Consent and Localisation Rules', 'India Data Protection Act 2025 privacy law enforcement', 1, 'india-data-protection-act-2025-enforcement', 'india'),
(18, 'India and UAE Launch Cross-Border Instant Payment Link Between UPI and AANI', '<p>India and the UAE activated a real-time cross-border payment corridor linking India Unified Payments Interface with the UAE instant payment system AANI, allowing the over 3.5 million Indian expatriates in the Gulf nation to send money to India in seconds at near-zero fees. The launch was announced jointly by RBI Governor Sanjay Malhotra and UAE Central Bank Governor Khaled Humaid Al Tameemi in Dubai. Transfer limits are set at Rs 2 lakh per transaction for individuals, with a daily cap of Rs 5 lakh. The corridor is built on the ISO 20022 messaging standard and is designed to expand to five additional Gulf Cooperation Council countries by end of 2026. NPCI International, which manages UPI linkages abroad, said the UAE corridor processed over 100,000 transactions within the first six hours of launch.</p>', 'India and UAE activate UPI-AANI cross-border instant payment link, enabling near-zero fee transfers for 3.5 million Indian expats.', '15 February 2026', '2026-02-15 10:00:00', 'news-india-018.webp', 'news-banner-india-018.webp', 1, 1, 'On', 'India UAE UPI AANI Cross Border Payment 2026', 'UPI UAE, India UAE payment, NPCI AANI, Indian expat remittance Gulf', 'India and UAE launch UPI-AANI real-time cross-border payments enabling instant transfers for Indian expats in the Gulf.', 5, 'India UAE UPI AANI Payment Link 2026', 'India and UAE Launch Cross-Border Instant Payment Link Between UPI and AANI', 'India UAE UPI AANI cross border payment 2026', 1, 'india-uae-upi-aani-cross-border-payment', 'india'),
(19, 'India Agriculture Ministry Launches PM-PRANAM Scheme to Reduce Chemical Fertiliser Use', '<p>The Union Ministry of Agriculture formally launched the PM Programme for Restoration, Awareness, Nourishment and Amelioration of Mother Earth (PM-PRANAM), a nationwide incentive scheme designed to shift farmers away from chemical fertilisers toward natural and bio-alternatives. States that reduce chemical fertiliser consumption below their three-year average will receive a grant equivalent to 50% of the subsidy savings generated, to be reinvested in farmer welfare schemes. The scheme targets a 20% reduction in chemical fertiliser consumption nationally by 2028, which would reduce India annual fertiliser import bill by an estimated $4 billion. The Agriculture Ministry has partnered with 1,500 krishi vigyan kendras across the country to provide farmers with free bio-input kits and training. Ten pilot districts in Rajasthan, Maharashtra, and Karnataka have already shown 15% reductions in urea use under early trial deployments.</p>', 'India launches PM-PRANAM to cut chemical fertiliser use by 20% by 2028, saving $4 billion in imports with state incentive grants.', '08 March 2026', '2026-03-08 09:00:00', 'news-india-019.webp', 'news-banner-india-019.webp', 1, 1, 'On', 'PM-PRANAM Scheme India Fertiliser Reduction 2026', 'PM-PRANAM, India natural farming, fertiliser reduction India, bio inputs agriculture', 'India launches PM-PRANAM to reduce chemical fertiliser use by 20% by 2028, targeting $4 billion in import savings.', 5, 'PM-PRANAM Fertiliser Reduction Scheme India', 'India Agriculture Ministry Launches PM-PRANAM Scheme to Reduce Chemical Fertiliser Use', 'India PM-PRANAM fertiliser reduction scheme 2026', 1, 'india-pm-pranam-chemical-fertiliser-reduction', 'india'),
(20, 'India Post Payments Bank Crosses 100 Million Account Milestone', '<p>India Post Payments Bank has crossed 100 million active accounts, cementing its position as India largest payments bank by account base and one of the most extensive financial inclusion networks in the world. IPPB, which operates through 1.65 lakh post offices and a network of 450,000 doorstep banking service providers known as Gramin Dak Sevaks, has brought banking access to 87% of accounts held by first-time formal banking users from rural India. The bank reported total deposits of Rs 22,000 crore and monthly transaction values exceeding Rs 15,000 crore. The Communications Ministry announced IPPB will integrate with DigiLocker to allow account holders to access government benefit disbursements, pension payments, and insurance premiums through a single platform. Digital Financial Literacy camps have been completed in over 600 districts since launch.</p>', 'India Post Payments Bank reaches 100 million accounts, becoming India largest payments bank through 1.65 lakh post offices.', '20 March 2026', '2026-03-20 09:00:00', 'news-india-020.webp', 'news-banner-india-020.webp', 1, 1, 'On', 'India Post Payments Bank 100 Million Accounts 2026', 'IPPB 100 million, India Post Payments Bank, financial inclusion India, rural banking', 'India Post Payments Bank crosses 100 million accounts, the largest payments bank serving rural India through post offices.', 5, 'India Post Payments Bank 100 Million', 'India Post Payments Bank Crosses 100 Million Account Milestone', 'India Post Payments Bank 100 million accounts 2026', 1, 'india-post-payments-bank-100-million-accounts', 'india'),
(21, 'Anthropic Releases Claude 4 with Extended Context and Autonomous Agent Capabilities', '<p>Anthropic released Claude 4, its most capable AI model family to date, featuring a one-million-token context window that can process entire legal libraries, codebases, or multi-year research corpora in a single prompt. The model introduces autonomous agent capabilities, allowing it to browse the web, write and execute code, manage files, and coordinate multi-step workflows without human intervention between steps. Claude 4 scored state-of-the-art results on the MMLU Pro, GPQA Diamond, and HumanEval benchmarks, surpassing all previously published models on graduate-level scientific reasoning tasks. Anthropic also released the Claude 4 API to enterprise customers in India and Southeast Asia as part of a dedicated emerging markets programme at subsidised token rates. The company said Claude 4 embeds Constitutional AI principles at a deeper architectural level than any previous model, making refusals more contextually nuanced and factual outputs more reliable.</p>', 'Anthropic releases Claude 4 with a 1M-token context window, autonomous agent capabilities, and state-of-the-art benchmark results.', '10 March 2025', '2025-03-10 18:00:00', 'news-tech-001.webp', 'news-banner-tech-001.webp', 2, 2, 'On', 'Anthropic Claude 4 Release AI 2025', 'Claude 4, Anthropic AI, Claude model 2025, AI agent capabilities', 'Anthropic releases Claude 4 with 1M token context, autonomous agents, and leading benchmark performance.', 5, 'Anthropic Claude 4 Release 2025', 'Anthropic Releases Claude 4 with Extended Context and Autonomous Agent Capabilities', 'Anthropic Claude 4 release AI agent 2025', 1, 'anthropic-claude-4-extended-context-autonomous-agents', 'technology'),
(22, 'Google Unveils Project Astra: A Universal AI Assistant Running on Smart Glasses', '<p>Google demonstrated Project Astra at its annual I/O developer conference, unveiling a universal AI assistant embedded into a new generation of augmented reality smart glasses developed in partnership with Warby Parker. Astra uses a continuous multimodal stream from the glasses camera and microphone to answer questions about the physical world in real time, reading signage, identifying objects, suggesting navigation, and translating spoken conversations simultaneously. The demonstration showed Astra identifying a complex circuit board and suggesting a repair, reading a foreign-language menu and summarising dishes, and navigating a building by reading floor maps. Google confirmed Astra is powered by Gemini Ultra 2 running partly on-device and partly on cloud inference. India-based software developers are among the first cohort invited to build third-party applications for the Astra platform via the Project Astra SDK.</p>', 'Google unveils Project Astra smart glasses with real-time AI vision, translation, and object recognition powered by Gemini Ultra 2.', '14 May 2025', '2025-05-14 18:00:00', 'news-tech-002.webp', 'news-banner-tech-002.webp', 2, 2, 'On', 'Google Project Astra Smart Glasses AI 2025', 'Google Project Astra, AI smart glasses, Gemini Ultra 2, AR glasses AI', 'Google unveils Project Astra smart glasses with real-time AI vision and universal assistant powered by Gemini Ultra 2.', 5, 'Google Project Astra Smart Glasses AI', 'Google Unveils Project Astra: A Universal AI Assistant Running on Smart Glasses', 'Google Project Astra AI smart glasses 2025', 1, 'google-project-astra-universal-ai-smart-glasses', 'technology'),
(23, 'Nvidia Launches Blackwell Ultra GPUs Claiming 4x Performance Over Hopper', '<p>Nvidia unveiled its next-generation Blackwell Ultra GPU architecture at the GPU Technology Conference in San Jose, claiming a fourfold increase in AI training throughput compared to the H100 Hopper generation. The flagship GB300 NVL72 system packs 72 Blackwell Ultra GPUs in a single rack-scale unit and delivers an aggregate 720 petaflops of FP8 AI performance. Nvidia CEO Jensen Huang said every major hyperscaler — including Microsoft, Amazon, Google, and Meta — had already placed Blackwell Ultra orders representing over $80 billion in combined commitments. The chips use a new NVLink 5 interconnect that doubles inter-GPU bandwidth to 3.6 terabytes per second, enabling larger models to be trained across fewer physical servers. India Tata Consultancy Services and Infosys have secured Blackwell Ultra allocations for their enterprise AI divisions.</p>', 'Nvidia launches Blackwell Ultra GPUs with 4x Hopper performance and $80 billion in hyperscaler orders already placed.', '18 March 2025', '2025-03-18 20:00:00', 'news-tech-003.webp', 'news-banner-tech-003.webp', 2, 2, 'On', 'Nvidia Blackwell Ultra GPU Launch 2025', 'Nvidia Blackwell Ultra, GB300, AI GPU 2025, Nvidia GTC', 'Nvidia unveils Blackwell Ultra GPUs with 4x performance over Hopper and $80B in committed hyperscaler orders.', 5, 'Nvidia Blackwell Ultra GPU 2025', 'Nvidia Launches Blackwell Ultra GPUs Claiming 4x Performance Over Hopper', 'Nvidia Blackwell Ultra GPU launch GTC 2025', 1, 'nvidia-blackwell-ultra-gpu-4x-hopper-performance', 'technology'),
(24, 'Microsoft Integrates Copilot Across Windows 12 as Default AI Layer', '<p>Microsoft officially released Windows 12, which ships with Copilot embedded at the operating system level as a persistent AI layer rather than a standalone application. Copilot in Windows 12 can summarise documents open in any application, draft replies to emails without switching windows, generate images directly from the clipboard, and manage system settings through natural language commands. The AI layer runs a hybrid inference model using Qualcomm and Intel neural processing units for local tasks and Azure cloud for heavier workloads. Microsoft confirmed Windows 12 will roll out as a free upgrade to Windows 11 users starting March 2026 and will require at least 16 gigabytes of RAM and a compatible NPU chip. Privacy advocates have urged Microsoft to provide opt-out controls for users who do not wish their on-screen content to be processed by the AI layer.</p>', 'Microsoft releases Windows 12 with Copilot as a system-level AI layer offering document summarisation, drafting, and system control.', '25 September 2025', '2025-09-25 17:00:00', 'news-tech-004.webp', 'news-banner-tech-004.webp', 2, 2, 'On', 'Microsoft Windows 12 Copilot AI Launch 2025', 'Windows 12, Microsoft Copilot, AI operating system, Windows 12 release', 'Microsoft releases Windows 12 with Copilot as a native OS-level AI layer handling documents, email, and system settings.', 5, 'Microsoft Windows 12 Copilot AI', 'Microsoft Integrates Copilot Across Windows 12 as Default AI Layer', 'Microsoft Windows 12 Copilot AI layer 2025', 1, 'microsoft-windows-12-copilot-ai-layer', 'technology'),
(25, 'Reliance Jio Partners with SpaceX for Hybrid 5G-Starlink Rural Coverage', '<p>Reliance Jio announced a strategic partnership with SpaceX to deploy a hybrid network combining Jio 5G terrestrial infrastructure with Starlink low-Earth orbit satellite backhaul for rural and remote areas across India where laying fibre is economically unviable. The partnership will cover an estimated 250,000 villages with reliable broadband within three years. Jio subscribers in covered areas will experience seamless handoff between terrestrial 5G and satellite connectivity managed by a unified network management platform. The venture will use direct-to-device satellite connectivity available from the next generation of Starlink satellites, allowing compatible smartphones to connect to the satellite layer without a dish receiver. Analysts estimate the partnership could bring reliable connectivity to India 200 million most digitally excluded residents and create a template replicated by telecoms across Africa and Southeast Asia.</p>', 'Jio and SpaceX partner to bring hybrid 5G-Starlink coverage to 250,000 rural Indian villages using direct-to-device satellite technology.', '05 April 2025', '2025-04-05 09:00:00', 'news-tech-005.webp', 'news-banner-tech-005.webp', 2, 2, 'On', 'Jio SpaceX Starlink Rural India 5G Satellite 2025', 'Jio Starlink, Reliance SpaceX, rural India internet, 5G satellite hybrid', 'Jio and SpaceX partner for hybrid 5G-Starlink coverage in 250,000 Indian villages via direct-to-device satellite.', 5, 'Jio SpaceX Starlink Rural India Partnership', 'Reliance Jio Partners with SpaceX for Hybrid 5G-Starlink Rural Coverage', 'Jio SpaceX Starlink hybrid 5G rural India 2025', 1, 'jio-spacex-starlink-hybrid-5g-rural-india', 'technology'),
(26, 'South Korea Launches World First Commercial Quantum Network Across Five Cities', '<p>South Korea national telecommunications company KT Corporation activated the world first commercial quantum cryptography communication network spanning Seoul, Busan, Daejeon, Incheon, and Gwangju, a total backbone distance of over 1,000 kilometres. The network uses quantum key distribution to generate encryption keys that are physically impossible to intercept without detection, providing communication security that no classical supercomputer can crack. South Korean government ministries, banking regulators, and defence agencies were the first institutions migrated to the quantum-secure network. The Korean government invested approximately $850 million in the project over seven years. Telecom experts worldwide have noted the rollout as the first proof that quantum communication is commercially and operationally viable at national scale, prompting parallel investment acceleration in the EU, United States, and India.</p>', 'South Korea activates the world first commercial quantum cryptography network across five cities, spanning over 1,000 kilometres.', '20 June 2025', '2025-06-20 09:00:00', 'news-tech-006.webp', 'news-banner-tech-006.webp', 2, 2, 'On', 'South Korea Quantum Network Commercial 2025', 'quantum network South Korea, QKD commercial, quantum cryptography, KT Corporation', 'South Korea launches world first commercial quantum cryptography network across five cities spanning 1,000 km.', 5, 'South Korea Quantum Network World First', 'South Korea Launches World First Commercial Quantum Network Across Five Cities', 'South Korea quantum network commercial QKD 2025', 1, 'south-korea-commercial-quantum-network-five-cities', 'technology'),
(27, 'Apple Intelligence Gains Real-Time Language Translation in iOS 19', '<p>Apple released iOS 19, centred on major advances in its Apple Intelligence AI platform, most notably a real-time live translation feature embedded at the system level that can translate conversations, video calls, and on-screen text in 32 languages simultaneously without sending audio to the cloud. The feature runs entirely on the A19 Bionic chip neural engine, ensuring that spoken conversations remain private and are never stored or transmitted. Apple also introduced a Personal Context Engine in iOS 19 that connects the AI to calendar events, emails, messages, and contacts to generate hyper-personalised suggestions and automate routine tasks. Indian users gain support for nine Indian languages in Apple Intelligence for the first time, including Marathi, Gujarati, Punjabi, and Odia. The update also features an AI-generated daily briefing summarising overnight news, messages, and schedule conflicts each morning.</p>', 'Apple iOS 19 brings on-device live translation in 32 languages and nine Indian language additions to Apple Intelligence.', '16 September 2025', '2025-09-16 18:00:00', 'news-tech-007.webp', 'news-banner-tech-007.webp', 2, 2, 'On', 'Apple iOS 19 Apple Intelligence Translation 2025', 'iOS 19, Apple Intelligence, live translation iPhone, Indian language Apple', 'Apple iOS 19 brings on-device live translation in 32 languages and expands Apple Intelligence to nine Indian languages.', 5, 'Apple iOS 19 Intelligence Translation', 'Apple Intelligence Gains Real-Time Language Translation in iOS 19', 'Apple iOS 19 Apple Intelligence translation Indian languages 2025', 1, 'apple-ios-19-intelligence-real-time-translation', 'technology'),
(28, 'OpenAI Deploys o3 Reasoning Model for Scientific Discovery in Partnership with CERN', '<p>OpenAI announced a research partnership with CERN, the European Organisation for Nuclear Research, to deploy its o3 advanced reasoning model to assist physicists in analysing petabytes of data from the Large Hadron Collider. The model has been fine-tuned on a corpus of 200,000 particle physics papers and can generate hypotheses, design experiments, and identify anomalous collision events that human analysts may overlook in the vast data volume. In its first eight weeks of operation, the system flagged 17 anomalous particle interaction signatures for deeper human investigation, three of which are currently under formal review as potential beyond-standard-model phenomena. CERN Director-General Fabiola Gianotti described the partnership as a new paradigm for AI-assisted fundamental science. India Tata Institute of Fundamental Research is listed as a collaborating institution in the partnership.</p>', 'OpenAI and CERN deploy the o3 reasoning model for particle physics analysis, flagging 17 anomalies in LHC data in eight weeks.', '12 October 2025', '2025-10-12 14:00:00', 'news-tech-008.webp', 'news-banner-tech-008.webp', 2, 2, 'On', 'OpenAI o3 CERN Particle Physics AI 2025', 'OpenAI o3 model, CERN AI, particle physics AI, LHC data analysis', 'OpenAI and CERN partner to use o3 reasoning model on LHC data, flagging 17 anomalies in first eight weeks.', 5, 'OpenAI o3 CERN Physics Partnership', 'OpenAI Deploys o3 Reasoning Model for Scientific Discovery in Partnership with CERN', 'OpenAI o3 CERN particle physics AI discovery 2025', 1, 'openai-o3-cern-scientific-discovery-partnership', 'technology'),
(29, 'EU Activates AI Act Obligations for General Purpose AI Models', '<p>The European Union Artificial Intelligence Act reached its first major enforcement milestone as obligations on providers of General Purpose AI models — defined as models trained on more than 10 to the power of 25 floating point operations — formally took effect across all 27 member states. Providers including OpenAI, Google, Meta, and Anthropic must now maintain technical documentation, publish model capability summaries, implement copyright compliance measures, and undergo adversarial testing by approved third-party auditors. Models classified as presenting systemic risk — those exceeding 10 to the power of 26 FLOPs — face additional incident reporting requirements. Non-compliance can attract fines of up to 3% of global annual turnover. The AI Office within the European Commission has begun its first formal assessments of the largest frontier models, with initial findings expected in early 2026.</p>', 'EU AI Act GPAI obligations activate, requiring frontier model providers to document capabilities, audit systems, and report incidents.', '02 August 2025', '2025-08-02 09:00:00', 'news-tech-009.webp', 'news-banner-tech-009.webp', 2, 2, 'On', 'EU AI Act GPAI Obligations Activate 2025', 'EU AI Act, GPAI model regulation, AI regulation Europe, AI Office EU', 'EU AI Act activates GPAI obligations requiring frontier model providers to document, audit, and report incidents.', 5, 'EU AI Act GPAI Obligations 2025', 'EU Activates AI Act Obligations for General Purpose AI Models', 'EU AI Act GPAI obligations frontier models 2025', 1, 'eu-ai-act-gpai-obligations-activated-2025', 'technology');
INSERT INTO `tbl_news` (`news_id`, `news_title`, `news_content`, `news_content_short`, `news_date`, `published_at`, `photo`, `banner`, `category_id`, `author_id`, `comment`, `meta_title`, `meta_keyword`, `meta_description`, `lang_id`, `stitle`, `title`, `img_alt`, `domain_id`, `encode_title`, `type`) VALUES
(30, 'India Launches MeitY AI Compute Grid with 10,000 GPUs for Researchers', '<p>The Ministry of Electronics and Information Technology launched the India AI Compute Grid, a publicly accessible GPU cluster comprising 10,000 high-performance accelerators distributed across data centres in Pune, Hyderabad, and Chennai, available at subsidised rates to Indian universities, government research institutions, and DPIIT-recognised startups. The grid, built under the IndiaAI Mission, offers Nvidia H100 and AMD MI300X GPUs accessible through a cloud portal with allocations made through a competitive peer-reviewed grant process. Initial allocation rounds received 1,400 applications from 62 institutions in 18 states. The grid gives Indian researchers affordable access to the same computational scale used by frontier AI labs globally. The government has committed to expanding the grid to 50,000 GPUs by 2027, with dedicated partitions reserved for healthcare, agriculture, and defence research applications.</p>', 'India launches the MeitY AI Compute Grid of 10,000 GPUs for subsidised research access under the IndiaAI Mission.', '25 November 2025', '2025-11-25 10:00:00', 'news-tech-010.webp', 'news-banner-tech-010.webp', 2, 2, 'On', 'India MeitY AI Compute Grid GPU Research 2025', 'IndiaAI compute grid, MeitY GPU cluster, India AI research infrastructure, H100 India', 'India launches 10,000-GPU AI Compute Grid under MeitY for subsidised university and startup research access.', 5, 'India MeitY AI Compute Grid 10000 GPU', 'India Launches MeitY AI Compute Grid with 10,000 GPUs for Researchers', 'India MeitY AI compute grid GPU research 2025', 1, 'india-meitY-ai-compute-grid-10000-gpus', 'technology'),
(31, 'Waymo Expands Autonomous Robotaxi Service to 12 US Cities', '<p>Waymo, the autonomous vehicle subsidiary of Alphabet, announced a major expansion of its fully driverless commercial robotaxi service to 12 additional US cities over 2025 and 2026, following profitable operations in San Francisco, Phoenix, and Los Angeles. The new cities include Austin, Chicago, Miami, Nashville, Denver, and seven others across the Sun Belt and Midwest. Waymo 6th generation Jaguar I-PACE robotaxi fleet will expand from its current 700 vehicles to over 3,000 vehicles by the end of 2026. The company reported it has completed over 10 million commercial robotaxi trips with zero at-fault serious accidents, a safety record that regulators have cited as justification for accelerated licensing. Waymo has also opened discussions with Tata Motors about manufacturing vehicle platforms in India for a potential future Asia expansion.</p>', 'Waymo expands its driverless robotaxi service to 12 US cities with a fleet growing to 3,000 vehicles by end of 2026.', '15 January 2026', '2026-01-15 10:00:00', 'news-tech-011.webp', 'news-banner-tech-011.webp', 2, 2, 'On', 'Waymo Robotaxi Expansion 12 US Cities 2026', 'Waymo expansion, driverless taxi US, Waymo robotaxi, autonomous vehicle 2026', 'Waymo expands driverless robotaxi service to 12 US cities, growing its fleet to 3,000 vehicles by end of 2026.', 5, 'Waymo Robotaxi 12 Cities Expansion', 'Waymo Expands Autonomous Robotaxi Service to 12 US Cities', 'Waymo autonomous robotaxi expansion US cities 2026', 1, 'waymo-autonomous-robotaxi-expansion-12-us-cities', 'technology'),
(32, 'India Unveils BharatSat-1 Indigenous Satellite Communication Platform', '<p>The Department of Telecommunications unveiled BharatSat-1, India first domestically developed commercial satellite communication platform designed to compete with Starlink, OneWeb, and Amazon Kuiper in providing broadband internet via low-Earth orbit satellites. The programme, executed by New Space India Limited and three private sector partners including Larsen and Toubro and Tata Advanced Systems, will deploy an initial constellation of 198 satellites at 550 kilometres altitude beginning in late 2026. BharatSat-1 is designed to provide 100 to 300 Mbps broadband at latency below 40 milliseconds with ground terminals priced at under Rs 8,000. The spectrum allocation, licensing, and orbital slot registration have been completed. Officials said BharatSat-1 would directly serve India strategic needs in border areas and island territories where no terrestrial connectivity is viable.</p>', 'India unveils BharatSat-1, its indigenous low-Earth orbit broadband constellation targeting 100-300 Mbps at under Rs 8,000 terminals.', '20 February 2026', '2026-02-20 10:00:00', 'news-tech-012.webp', 'news-banner-tech-012.webp', 2, 2, 'On', 'BharatSat-1 India Satellite Broadband LEO 2026', 'BharatSat, India satellite internet, LEO constellation India, NSIL satellite', 'India unveils BharatSat-1 indigenous LEO satellite broadband with 198-satellite constellation and Rs 8,000 terminals.', 5, 'BharatSat-1 India Satellite Broadband', 'India Unveils BharatSat-1 Indigenous Satellite Communication Platform', 'BharatSat-1 India satellite broadband LEO 2026', 1, 'india-bharatsat-1-indigenous-satellite-broadband', 'technology'),
(33, 'Meta Releases Llama 4 Scout with 10 Million Token Context for Enterprises', '<p>Meta released Llama 4 Scout, the enterprise-grade variant of its open-weight Llama 4 family, featuring a landmark 10-million-token context window that can ingest entire corporate document repositories, multi-year correspondence archives, or complete software codebases in a single inference call. Scout is optimised for retrieval-augmented generation tasks and demonstrated superior performance to closed-source competitors on enterprise reasoning and long-document question answering benchmarks. Unlike consumer Llama variants, Scout is available under a commercial licence and includes Meta safety and content moderation layers. The model can run on eight H100 GPUs, making it affordable for mid-size enterprises without hyperscaler infrastructure. Wipro, Infosys, and HCL Technologies have each announced Llama 4 Scout-based enterprise AI products for Indian and global markets.</p>', 'Meta releases Llama 4 Scout with a 10M-token context window for enterprises, enabling full document corpus ingestion in a single call.', '10 March 2026', '2026-03-10 10:00:00', 'news-tech-013.webp', 'news-banner-tech-013.webp', 2, 2, 'On', 'Meta Llama 4 Scout Enterprise 10M Context 2026', 'Llama 4 Scout, Meta AI enterprise, 10 million token context, open weight LLM', 'Meta releases Llama 4 Scout with a 10M-token context window for enterprise RAG and document intelligence.', 5, 'Meta Llama 4 Scout Enterprise 10M Context', 'Meta Releases Llama 4 Scout with 10 Million Token Context for Enterprises', 'Meta Llama 4 Scout enterprise 10 million token context 2026', 1, 'meta-llama-4-scout-10-million-context-enterprise', 'technology'),
(34, 'Japan Activates World First Practical Quantum Computer at 100,000 Qubits', '<p>Japan RIKEN research institute and Fujitsu jointly activated what they describe as the world first practical-scale quantum computer reaching 100,000 physical qubits, a milestone that surpasses all previously announced quantum systems by an order of magnitude. The machine uses error-corrected superconducting qubits and demonstrated solving a 2,000-variable pharmaceutical molecular simulation problem 40,000 times faster than any classical supercomputer. Japanese Minister of Science Keiko Nagaoka called the activation a Sputnik moment for computing. The system is hosted at RIKEN Cluster for Pioneering Research in Wako, Saitama, and will be made accessible to international researchers through a cloud-based quantum computing portal. India Department of Science and Technology has formally applied for research access under the bilateral science and technology agreement with Japan.</p>', 'Japan activates a 100,000-qubit practical quantum computer at RIKEN, solving pharmaceutical simulations 40,000x faster than classical systems.', '28 February 2026', '2026-02-28 09:00:00', 'news-tech-014.webp', 'news-banner-tech-014.webp', 2, 2, 'On', 'Japan 100000 Qubit Quantum Computer RIKEN 2026', 'Japan quantum computer, 100000 qubit, RIKEN Fujitsu quantum, practical quantum computing', 'Japan activates 100,000-qubit practical quantum computer at RIKEN, the world largest, solving pharma simulations.', 5, 'Japan 100000 Qubit Quantum Computer', 'Japan Activates World First Practical Quantum Computer at 100,000 Qubits', 'Japan RIKEN 100000 qubit quantum computer 2026', 1, 'japan-100000-qubit-quantum-computer-riken', 'technology'),
(35, 'India Mandates AI Watermarking for All Synthetic Media Under IT Amendment', '<p>The Ministry of Electronics and Information Technology issued an amendment to the Information Technology Rules requiring all AI-generated images, audio, and video content published on Indian digital platforms to carry an embedded and visible watermark indicating synthetic origin by September 2026. The amendment applies to platforms with more than 5 million Indian users, covering social media, news websites, streaming services, and messaging platforms that permit content broadcasting. Platforms must also retain metadata logs linking synthetic content to the AI system that generated it for a minimum of 180 days, accessible to law enforcement upon court order. MEITY said the measure is designed to combat AI-generated deepfakes used in electoral misinformation, financial fraud, and non-consensual intimate imagery. Violations will attract penalties under the Digital Personal Data Protection Act and can result in platform blocking.</p>', 'India mandates AI watermarking on all synthetic media for platforms with 5M+ users, targeting deepfakes and electoral misinformation.', '18 January 2026', '2026-01-18 09:00:00', 'news-tech-015.webp', 'news-banner-tech-015.webp', 2, 2, 'On', 'India AI Watermarking Synthetic Media Deepfake Law 2026', 'AI watermark India, synthetic media regulation, deepfake law India, MEITY AI rules', 'India mandates watermarking for AI-generated content on large platforms to counter deepfakes and misinformation.', 5, 'India AI Watermark Synthetic Media Law', 'India Mandates AI Watermarking for All Synthetic Media Under IT Amendment', 'India AI watermarking synthetic media deepfake law 2026', 1, 'india-ai-watermarking-synthetic-media-it-amendment', 'technology'),
(36, 'Amazon Launches Alexa Plus with Autonomous Shopping and Smart Home AI', '<p>Amazon launched Alexa Plus, a dramatically upgraded version of its voice assistant powered by a proprietary large language model developed in-house under the Olympus programme. Alexa Plus can autonomously complete multi-step online shopping tasks — comparing prices, applying coupons, selecting delivery options, and completing checkout — without user confirmation at every step, within guardrails set by the user. The assistant also manages smart home ecosystems through natural conversation, coordinating devices from over 500 manufacturers on a unified AI layer. Amazon confirmed Alexa Plus will be available as a subscription at $9.99 per month or bundled with Prime. India launch is confirmed for Q3 2025, with an expanded Hinglish conversational mode that handles code-switching between Hindi and English natively. Amazon India said over 3 million Alexa-enabled devices are already active in Indian households.</p>', 'Amazon launches Alexa Plus with autonomous shopping, multi-step smart home control, and Hinglish support for India.', '26 February 2025', '2025-02-26 18:00:00', 'news-tech-016.webp', 'news-banner-tech-016.webp', 2, 2, 'On', 'Amazon Alexa Plus Launch AI 2025', 'Alexa Plus, Amazon AI assistant, Alexa upgrade 2025, smart home AI India', 'Amazon launches Alexa Plus with autonomous shopping and smart home AI, including Hinglish support for India.', 5, 'Amazon Alexa Plus Launch AI 2025', 'Amazon Launches Alexa Plus with Autonomous Shopping and Smart Home AI', 'Amazon Alexa Plus AI assistant launch India 2025', 1, 'amazon-alexa-plus-autonomous-shopping-ai-launch', 'technology'),
(37, 'China Deploys Humanoid Robot Workers in Auto Manufacturing Plants at Scale', '<p>Chinese technology conglomerate UBTECH Robotics announced deployment of its Walker S2 humanoid robots at scale across five major automotive manufacturing plants, including facilities operated by BYD, SAIC, and Geely. A total of 2,000 Walker S2 units are now performing tasks including body panel assembly, quality inspection, component installation, and logistics within the plants. The robots operate 20-hour shifts, require no protective equipment, and can switch between tasks by downloading new skill modules over the air in under four minutes. UBTECH said the per-robot deployment cost has fallen below $40,000 following breakthroughs in actuator and sensor manufacturing at scale. Chinese government officials described the deployment as a national industrial milestone and pledged to have 100,000 humanoid robots operational in Chinese factories by 2027.</p>', 'China deploys 2,000 UBTECH Walker S2 humanoid robots across BYD, SAIC, and Geely auto plants at $40,000 per unit.', '05 May 2025', '2025-05-05 09:00:00', 'news-tech-017.webp', 'news-banner-tech-017.webp', 2, 2, 'On', 'China Humanoid Robot Factory BYD UBTECH 2025', 'humanoid robot China factory, Walker S2, UBTECH robotics, BYD robot worker', 'China deploys 2,000 UBTECH humanoid robots in auto plants at $40,000 each, targeting 100,000 by 2027.', 5, 'China Humanoid Robot Factory Scale', 'China Deploys Humanoid Robot Workers in Auto Manufacturing Plants at Scale', 'China UBTECH humanoid robot factory manufacturing 2025', 1, 'china-humanoid-robots-auto-manufacturing-scale', 'technology'),
(38, 'DRDO Successfully Tests Hypersonic Missile Travelling at Mach 8', '<p>India Defence Research and Development Organisation successfully completed the maiden test flight of its Hypersonic Technology Demonstrator Vehicle Phase 2, a scramjet-powered hypersonic cruise missile prototype that reached a sustained speed of Mach 8 — eight times the speed of sound — over a flight duration of seven minutes. The test was conducted from a launch pad at Abdul Kalam Island in the Bay of Bengal, with the vehicle reaching an altitude of 32 kilometres before executing a guided terminal approach. With this test, India joined an elite group of nations — the United States, Russia, and China — that have demonstrated hypersonic strike capability. Defence Minister Rajnath Singh called the test a leap that fundamentally alters India strategic deterrence calculus. The missile is designed to defeat all current ballistic missile defence systems through its unpredictable flight trajectory.</p>', 'DRDO successfully tests a Mach 8 hypersonic cruise missile, making India the fourth nation with demonstrated hypersonic strike capability.', '12 June 2025', '2025-06-12 07:00:00', 'news-tech-018.webp', 'news-banner-tech-018.webp', 2, 2, 'On', 'India DRDO Hypersonic Missile Mach 8 Test 2025', 'DRDO hypersonic missile, India Mach 8, HSTDV Phase 2, India defence technology', 'DRDO tests Mach 8 hypersonic missile, making India the fourth nation with confirmed hypersonic strike capability.', 5, 'DRDO Hypersonic Missile Mach 8 India', 'DRDO Successfully Tests Hypersonic Missile Travelling at Mach 8', 'DRDO hypersonic missile Mach 8 India test 2025', 1, 'drdo-hypersonic-missile-mach-8-test-india', 'technology'),
(39, 'Global Internet Traffic Exceeds One Zettabyte Per Month for First Time', '<p>Cisco Annual Internet Report 2025 confirmed that global internet traffic crossed one zettabyte per month — equivalent to one trillion gigabytes — for the first time in recorded history, driven primarily by AI inference traffic, 8K video streaming, and the explosion of IoT device communications. AI-related traffic, including API calls to large language models, image generation services, and edge inference endpoints, now constitutes 18% of total global internet data flow, up from 3% in 2022. India ranks as the world third-largest contributor to internet traffic growth, behind the United States and China, with per-capita data consumption in India reaching 28 gigabytes per month. Subsea cable capacity investment hit a record $10 billion in 2024, with three new cables connecting India to Europe scheduled for 2026 completion.</p>', 'Global internet traffic crosses one zettabyte per month for the first time, with AI traffic now 18% of total global data flow.', '30 July 2025', '2025-07-30 09:00:00', 'news-tech-019.webp', 'news-banner-tech-019.webp', 2, 2, 'On', 'Global Internet Traffic One Zettabyte 2025', 'internet traffic zettabyte, global data consumption, AI internet traffic, Cisco report', 'Global internet traffic crosses 1 zettabyte per month with AI traffic at 18% and India as third-largest contributor.', 5, 'Global Internet One Zettabyte Per Month', 'Global Internet Traffic Exceeds One Zettabyte Per Month for First Time', 'global internet traffic zettabyte AI 2025', 1, 'global-internet-traffic-one-zettabyte-per-month', 'technology'),
(40, 'Tata Motors Launches Avinya EV Platform with 600km Range and 10-Minute Fast Charge', '<p>Tata Motors unveiled its next-generation all-electric vehicle platform, Avinya, at a global launch event in Mumbai that drew automotive journalists from 40 countries. The platform features a proprietary solid-state battery pack with a certified range of 600 kilometres and a 10-minute ultra-fast charging capability from 10% to 80% using 500 kW chargers. The first production vehicle on the Avinya platform, the Avinya SUV, will go on sale in India in Q1 2026 at an anticipated price of Rs 22 lakh, positioning it as the most affordable long-range EV in the Indian market. The platform uses a skateboard architecture compatible with sedans, SUVs, and MPVs, with international markets including the UK and Germany confirmed for launches by 2027. Tata Motors CEO Shailesh Chandra said Avinya will manufacture entirely in India with 85% localisation from day one.</p>', 'Tata Motors unveils the Avinya EV platform with 600km range and 10-minute fast charge, launching the first SUV at Rs 22 lakh.', '18 October 2025', '2025-10-18 10:00:00', 'news-tech-020.webp', 'news-banner-tech-020.webp', 2, 2, 'On', 'Tata Avinya EV Platform 600km Range India 2025', 'Tata Avinya, Tata EV platform, 600km range EV India, solid state battery India', 'Tata Motors launches Avinya EV platform with 600km range and 10-minute fast charge, first SUV at Rs 22 lakh.', 5, 'Tata Avinya EV 600km Fast Charge', 'Tata Motors Launches Avinya EV Platform with 600km Range and 10-Minute Fast Charge', 'Tata Avinya EV 600km range fast charge India 2025', 1, 'tata-avinya-ev-platform-600km-10-minute-charge', 'technology'),
(41, 'India Wins Thomas Cup Badminton for Third Consecutive Time', '<p>India men badminton team won the Thomas Cup for the third consecutive time in Chengdu, China, defeating South Korea 3-2 in a tense final that stretched to all five matches. H.S. Prannoy delivered the decisive rubber, winning 21-18, 18-21, 21-17 against world number five Jeon Hyeok-jin in a match lasting one hour and forty minutes. Lakshya Sen had given India an early 2-0 lead before South Korea levelled, making Prannoy win essential. Coach Pullela Gopichand praised the team depth, noting India had used nine different players across the tournament without any individual carrying an excessive match load. Prime Minister Modi called the team to offer congratulations and announced the entire squad would receive the Arjuna Award at the next national sports awards ceremony.</p>', 'India wins the Thomas Cup for the third consecutive time in Chengdu, defeating South Korea 3-2 in a five-match final.', '05 May 2025', '2025-05-05 20:00:00', 'news-sports-001.webp', 'news-banner-sports-001.webp', 3, 3, 'On', 'India Thomas Cup 2025 Badminton Third Consecutive', 'Thomas Cup 2025, India badminton, Prannoy, Lakshya Sen', 'India wins the Thomas Cup for the third straight time in Chengdu, defeating South Korea 3-2 in the final.', 5, 'India Thomas Cup 2025 Third Title', 'India Wins Thomas Cup Badminton for Third Consecutive Time', 'India Thomas Cup 2025 badminton third consecutive win', 1, 'india-thomas-cup-2025-third-consecutive', 'sports'),
(42, 'Novak Djokovic Wins Record 25th Grand Slam at Roland Garros', '<p>Novak Djokovic extended his own Grand Slam record to 25 titles by winning his fourth consecutive Roland Garros crown, defeating Spain world number two Carlos Alcaraz 7-5, 4-6, 6-2, 6-3 in a final that highlighted the generational tension between the ageless champion and his heir apparent. Djokovic, 38, became the first man to win a Grand Slam at every age from 17 to 38, a feat that statisticians describe as without precedent in professional sports. The victory ended a heated rivalry run in which Alcaraz had defeated Djokovic at Wimbledon and the US Open in 2024. The Croatian born Serb received a standing ovation lasting over four minutes from the Centre Court audience before delivering an emotional speech in French honouring Paris as his second home. Djokovic has now won Roland Garros four times, Wimbledon seven times, the Australian Open ten times, and the US Open four times.</p>', 'Djokovic wins a record 25th Grand Slam at Roland Garros, defeating Alcaraz 4 sets in a final for the ages.', '08 June 2025', '2025-06-08 19:30:00', 'news-sports-002.webp', 'news-banner-sports-002.webp', 3, 3, 'On', 'Djokovic 25th Grand Slam Roland Garros 2025', 'Djokovic Grand Slam record, Roland Garros 2025, Djokovic Alcaraz final', 'Djokovic wins record 25th Grand Slam at Roland Garros, defeating Alcaraz in four sets to extend his own record.', 5, 'Djokovic 25th Grand Slam Record Roland Garros', 'Novak Djokovic Wins Record 25th Grand Slam at Roland Garros', 'Djokovic 25 Grand Slam Roland Garros 2025', 1, 'djokovic-25th-grand-slam-roland-garros-2025', 'sports'),
(43, 'Real Madrid Win Champions League for the Fifth Consecutive Season', '<p>Real Madrid claimed an unprecedented fifth consecutive UEFA Champions League title, defeating Paris Saint-Germain 2-1 in the final at the Allianz Arena in Munich. Kylian Mbappe, making his first Champions League final appearance against his former club, was the architect of both goals before being taken off with a minor knock in the 76th minute. The victory made Real Madrid the first club in the history of the competition to win five consecutive European titles, surpassing their own record of three consecutive wins between 2016 and 2018. Jude Bellingham, named Player of the Tournament with eight goal contributions across 12 appearances, delivered an emotional post-match interview calling the achievement something that will never be repeated in football. The squad paraded through central Madrid the following morning before an estimated crowd of four million people.</p>', 'Real Madrid win an unprecedented fifth consecutive Champions League, defeating PSG 2-1 in the Munich final.', '31 May 2025', '2025-05-31 21:45:00', 'news-sports-003.webp', 'news-banner-sports-003.webp', 3, 3, 'On', 'Real Madrid Champions League 2025 Fifth Consecutive', 'Champions League 2025, Real Madrid, Mbappe, Bellingham, UCL final', 'Real Madrid win a record fifth consecutive Champions League, defeating PSG 2-1 in Munich with Mbappe scoring twice.', 5, 'Real Madrid Champions League 5th Consecutive', 'Real Madrid Win Champions League for the Fifth Consecutive Season', 'Real Madrid Champions League 2025 fifth consecutive title', 1, 'real-madrid-champions-league-fifth-consecutive-2025', 'sports'),
(44, 'Satwiksairaj Rankireddy and Chirag Shetty Win All England Open', '<p>Indian doubles pair Satwiksairaj Rankireddy and Chirag Shetty claimed the All England Open Badminton Championships title in Birmingham, becoming the first Indian men doubles pair to win the most prestigious title in the sport since its founding in 1899. The world number one pair defeated Chinese pair Liu Yuchen and Ou Xuanyi 21-14, 18-21, 21-16 in a final lasting one hour and 28 minutes. The win adds the All England title to a collection that already includes two World Championship gold medals and an Olympic bronze. The duo dedicated their victory to their coach Mathias Boe and expressed hope that the win would inspire a new generation of Indian shuttlers to take up doubles. The Badminton World Federation ranked the performance the highest-quality men doubles final in five years based on rally speed, court coverage, and deceptive shot frequency metrics.</p>', 'Satwik and Chirag become first Indians to win the All England Open, defeating the Chinese world number two pair in three sets.', '17 March 2025', '2025-03-17 18:30:00', 'news-sports-004.webp', 'news-banner-sports-004.webp', 3, 3, 'On', 'Satwik Chirag All England Open Badminton 2025', 'Satwik Chirag All England, India badminton doubles, All England 2025', 'Satwik and Chirag become first Indians to win the All England Open Badminton title in the championship history.', 5, 'Satwik Chirag All England Open 2025', 'Satwiksairaj Rankireddy and Chirag Shetty Win All England Open', 'Satwik Chirag All England Open badminton 2025', 1, 'satwik-chirag-all-england-open-badminton-2025', 'sports'),
(45, 'Argentina Defends FIFA World Cup Title Beating England 3-1 in Final', '<p>Argentina defended their FIFA World Cup title at the 2026 tournament co-hosted by the United States, Canada, and Mexico, defeating England 3-1 in the final played at the Rose Bowl in Los Angeles. Julian Alvarez scored twice and set up Lautaro Martinez for the third, while Harry Kane replied with a consolation penalty to reach 100 international goals before a worldwide audience estimated at 1.6 billion. Lionel Messi, now 38 and playing what is expected to be his final World Cup, was named tournament ambassador and carried the trophy in a ceremonial presentation before the final. Coach Lionel Scaloni called it the greatest achievement in Argentine football history to defend a World Cup title after 44 years. The tournament attracted record revenue of $15 billion and the highest cumulative stadium attendances in World Cup history.</p>', 'Argentina defends the FIFA World Cup 2026, beating England 3-1 in Los Angeles as Alvarez scores twice in a historic final.', '19 July 2026', '2026-07-19 21:00:00', 'news-sports-005.webp', 'news-banner-sports-005.webp', 3, 3, 'On', 'FIFA World Cup 2026 Argentina England Final', 'FIFA World Cup 2026, Argentina champion, World Cup final 2026, Alvarez Messi', 'Argentina defends the World Cup title, beating England 3-1 in the Los Angeles final as Alvarez scores twice.', 5, 'FIFA World Cup 2026 Argentina Champion', 'Argentina Defends FIFA World Cup Title Beating England 3-1 in Final', 'Argentina FIFA World Cup 2026 final England 3-1', 1, 'argentina-defends-fifa-world-cup-2026-england-final', 'sports'),
(46, 'Smriti Mandhana Named ICC Women Cricketer of the Year 2025', '<p>Smriti Mandhana was named the ICC Women Cricketer of the Year for 2025, recognising a season of outstanding consistency in which she scored 1,452 runs across all international formats at an average of 68.2. The award spans her performances across ICC Women World Cup qualifiers, bilateral series against England and Australia, and the ICC Women Championship. Mandhana became the first batter from any country to score centuries in five consecutive bilateral series in a calendar year. ICC CEO Geoff Allardice cited her technique, footwork against pace, and ability to anchor a chase under pressure as qualities that set her apart. Mandhana also led Run-a-Thon, a grassroots cricket participation drive that enrolled 400,000 girls across 12 Indian states in the sport for the first time during 2025.</p>', 'Smriti Mandhana wins ICC Women Cricketer of the Year 2025 after scoring 1,452 international runs at an average of 68.2.', '24 January 2026', '2026-01-24 12:00:00', 'news-sports-006.webp', 'news-banner-sports-006.webp', 3, 3, 'On', 'Smriti Mandhana ICC Women Cricketer Year 2025', 'Smriti Mandhana ICC award, ICC women cricket 2025, India women cricket', 'Smriti Mandhana named ICC Women Cricketer of the Year after a record season of 1,452 runs at 68.2 average.', 5, 'Smriti Mandhana ICC Women Cricketer 2025', 'Smriti Mandhana Named ICC Women Cricketer of the Year 2025', 'Smriti Mandhana ICC women cricketer year 2025', 1, 'smriti-mandhana-icc-women-cricketer-year-2025', 'sports'),
(47, 'India Men Hockey Team Wins Asian Champions Trophy with Perfect Record', '<p>India men hockey team won the Asian Champions Trophy in Rajgir, Bihar, completing the tournament with a perfect record of seven wins from seven matches, conceding only two goals across the competition. The final against Pakistan ended 4-0, with Harmanpreet Singh scoring a hat-trick from drag flicks — his sixth hat-trick for India in international hockey. India also broke the tournament record for goals scored in a single edition, netting 38 across seven matches. The home crowd of 38,000 at the newly constructed Rajgir Hockey Stadium created an electric atmosphere that players credited as a decisive factor. Chief Minister Nitish Kumar announced Rs 1 crore in prize money for each player. The win significantly boosted India ranking and confidence ahead of the Paris 2028 Olympic qualification pathway.</p>', 'India wins the Asian Champions Trophy hockey with a perfect 7-0 record, beating Pakistan 4-0 in the final in Rajgir.', '20 November 2025', '2025-11-20 19:00:00', 'news-sports-007.webp', 'news-banner-sports-007.webp', 3, 3, 'On', 'India Hockey Asian Champions Trophy 2025 Perfect Record', 'India hockey Asian Champions Trophy, Harmanpreet Singh hat trick, India hockey Rajgir', 'India wins Asian Champions Trophy hockey with a 7-0 perfect record, defeating Pakistan 4-0 in the Rajgir final.', 5, 'India Hockey Asian Champions Trophy 2025', 'India Men Hockey Team Wins Asian Champions Trophy with Perfect Record', 'India hockey Asian Champions Trophy 2025 perfect record', 1, 'india-hockey-asian-champions-trophy-2025-perfect', 'sports'),
(48, 'Lakshya Sen Wins BWF World Championships to Become World Number One', '<p>Lakshya Sen won the BWF World Badminton Championships in Paris, defeating defending champion Viktor Axelsen of Denmark 21-18, 20-22, 21-15 in a final that demonstrated the Indian has now surpassed the Dane in every technical aspect of the modern game. The victory propelled Sen to the world number one ranking for the first time in his career, making him the first Indian men singles player to hold the top spot since Prakash Padukone in the early 1980s. Sen, 24, has won five BWF Super 1000 events this season and went undefeated in 18 consecutive matches heading into the final. Prime Minister Modi hosted the squad at his residence the following afternoon in a reception attended by Indian sports icons including Abhinav Bindra, P.T. Usha, and Viswanathan Anand.</p>', 'Lakshya Sen wins the BWF World Championships in Paris, becoming India first men singles world number one since Prakash Padukone.', '28 August 2025', '2025-08-28 20:00:00', 'news-sports-008.webp', 'news-banner-sports-008.webp', 3, 3, 'On', 'Lakshya Sen BWF World Championships 2025 World Number One', 'Lakshya Sen world champion, BWF Worlds 2025, India badminton number one', 'Lakshya Sen wins BWF World Championship and becomes world number one, first Indian men singles to do so in decades.', 5, 'Lakshya Sen BWF World Champion 2025', 'Lakshya Sen Wins BWF World Championships to Become World Number One', 'Lakshya Sen BWF world championships world number one 2025', 1, 'lakshya-sen-bwf-world-champion-world-number-one', 'sports'),
(49, 'India Squad Finishes Third in 2026 Winter Olympics Medal Tally', '<p>India concluded its most successful Winter Olympics in history at the Milan-Cortina 2026 Games, finishing third on the overall medal tally with two gold medals, three silver medals, and four bronze medals across alpine skiing, figure skating, and cross-country skiing disciplines. The transformation was credited to the Khelo India Winter Games programme launched in 2021 that identified and developed athletes from Himachal Pradesh, Uttarakhand, and Jammu and Kashmir. Aryan Verma became the first Indian to win an Olympic gold medal in skiing, taking the men slalom title by 0.04 seconds over the French defending champion. Sports Minister Mansukh Mandaviya called the performance a watershed moment and announced a Rs 500 crore dedicated Winter Sports Academy to be built in Gulmarg, Kashmir.</p>', 'India finishes third at the 2026 Winter Olympics with 9 medals including two golds, its best-ever Winter Games performance.', '28 February 2026', '2026-02-28 20:00:00', 'news-sports-009.webp', 'news-banner-sports-009.webp', 3, 3, 'On', 'India Winter Olympics 2026 Medal Third Best Ever', 'India Winter Olympics 2026, Aryan Verma skiing, Milan-Cortina India medal', 'India finishes third in the 2026 Winter Olympics medal tally with 9 medals, its most successful Winter Games ever.', 5, 'India Winter Olympics 2026 Third Medal', 'India Squad Finishes Third in 2026 Winter Olympics Medal Tally', 'India Winter Olympics 2026 medal tally third best', 1, 'india-winter-olympics-2026-third-medal-tally', 'sports'),
(50, 'IPL 2025 Breaks Viewership Record with 600 Million Cumulative Audience', '<p>The Board of Control for Cricket in India confirmed that IPL 2025 set a new cumulative viewership record of 600 million unique individuals who watched at least one match across television and digital platforms over the seven-week tournament, surpassing the previous record of 505 million set in 2024. JioCinema, which holds the digital rights, reported 85 million concurrent viewers during the Mumbai Indians versus Chennai Super Kings match on May 18, the highest ever concurrent stream for any sporting event in India history. Total advertising revenue generated by IPL 2025 across all media crossed Rs 10,000 crore for the first time. International viewership was led by the United Kingdom, the United States, the UAE, and South Africa, reflecting the global reach of Indian cricket and the IPL brand.</p>', 'IPL 2025 sets a record with 600 million viewers, Rs 10,000 crore in ad revenue, and 85 million concurrent JioCinema streams.', '05 June 2025', '2025-06-05 10:00:00', 'news-sports-010.webp', 'news-banner-sports-010.webp', 3, 3, 'On', 'IPL 2025 Viewership Record 600 Million BCCI', 'IPL 2025 viewership, JioCinema record, IPL revenue, cricket streaming India', 'IPL 2025 sets a record 600 million cumulative viewers and Rs 10,000 crore ad revenue across TV and digital.', 5, 'IPL 2025 Viewership Record 600 Million', 'IPL 2025 Breaks Viewership Record with 600 Million Cumulative Audience', 'IPL 2025 viewership record 600 million JioCinema', 1, 'ipl-2025-viewership-record-600-million-audience', 'sports'),
(51, 'India Athletics Federation Breaks National Record in 4x100m Relay at World Relays', '<p>India men 4x100 metre relay team shattered the national record at the World Athletics Relays in Guangzhou, clocking 37.84 seconds to finish fourth overall and qualify directly for the Paris 2028 Olympics relay event. The quartet of Mohammed Anas, Amlan Borgohain, Srinivasa Gowda, and Gurindervir Singh completed the fastest recorded 4x100m in Indian history, breaking the previous mark of 38.24 seconds set at the 2023 Asian Games. World Athletics President Sebastian Coe personally congratulated the Indian federation, noting the improvement was one of the largest single-championship national record margins in relay history. Chief National Athletics Coach Radhakrishnan Nair said the achievement validated a two-year programme of sprint-specific periodisation and biomechanical coaching introduced after the Paris Olympics.</p>', 'India breaks the 4x100m relay national record with 37.84 seconds at World Relays, qualifying directly for Paris 2028 Olympics.', '12 May 2025', '2025-05-12 20:00:00', 'news-sports-011.webp', 'news-banner-sports-011.webp', 3, 3, 'On', 'India 4x100m Relay Record World Athletics 2025', 'India relay record, 4x100m India, World Athletics Relays, Paris 2028 qualifier', 'India men relay team sets 4x100m national record of 37.84s at World Relays, qualifying for Paris 2028 Olympics.', 5, 'India 4x100m Relay National Record 2025', 'India Athletics Federation Breaks National Record in 4x100m Relay at World Relays', 'India 4x100m relay national record World Athletics 2025', 1, 'india-4x100m-relay-national-record-world-relays', 'sports'),
(52, 'Formula E Indian Grand Prix Confirmed for Hyderabad in 2026 Season', '<p>The ABB FIA Formula E World Championship confirmed the return of Hyderabad as a round on the 2026 calendar, with the street circuit race scheduled to run along a redesigned 2.8-kilometre route through the HITEC City financial district. The announcement followed successful negotiations between the FIA, the Telangana government, and Formula E Operations. The race will be the only Formula E event in South Asia and is expected to draw 80,000 spectators across two race days. Telangana Chief Minister announced a Rs 75 crore investment to upgrade the temporary circuit infrastructure, grandstands, and fan zones. Mahindra Racing, the only Indian team in Formula E, confirmed it will unveil its new Gen3 Evo car at the Hyderabad launch event, giving home fans a first glimpse of the machine ahead of its competitive debut.</p>', 'Hyderabad confirmed for the Formula E World Championship in 2026, with Mahindra Racing to unveil its new car at the home race.', '10 September 2025', '2025-09-10 10:00:00', 'news-sports-012.webp', 'news-banner-sports-012.webp', 3, 3, 'On', 'Formula E Hyderabad 2026 India Grand Prix Mahindra', 'Formula E Hyderabad 2026, Mahindra Racing, India Formula E, electric racing India', 'Hyderabad returns to the Formula E calendar in 2026 with Mahindra Racing set to unveil its new car at the home race.', 5, 'Formula E Hyderabad 2026 Mahindra Racing', 'Formula E Indian Grand Prix Confirmed for Hyderabad in 2026 Season', 'Formula E Hyderabad India 2026 Mahindra Racing', 1, 'formula-e-hyderabad-india-2026-season', 'sports'),
(53, 'India Wins Davis Cup Final After 93-Year Wait', '<p>India won the Davis Cup for only the second time in their history, defeating Australia 3-2 in the final in Melbourne in a thrilling encounter that required all five rubbers to decide the victor. Ramkumar Ramanathan clinched the title-winning point by defeating Jordan Thompson 6-4, 5-7, 7-5 in a third-set tiebreak that left players and support staff in tears on the court. The doubles rubber, won by Satwik-Chirag over Purcell and Peers in four sets, had earlier given India the lead from which they never relinquished the advantage. India captain Zeeshan Ali described the victory as the culmination of three years of comprehensive investment in Indian tennis infrastructure. The last time India won the Davis Cup was in 1974 when Vijay Amritraj and Ramanathan Krishnan led the squad to the historic title.</p>', 'India wins the Davis Cup for the second time in 93 years, defeating Australia 3-2 in a five-rubber final in Melbourne.', '28 November 2025', '2025-11-28 19:00:00', 'news-sports-013.webp', 'news-banner-sports-013.webp', 3, 3, 'On', 'India Davis Cup 2025 Win Australia Final', 'India Davis Cup 2025, Ramanathan, Satwik Chirag, India tennis title', 'India wins the Davis Cup for the first time since 1974, defeating Australia 3-2 in a five-rubber Melbourne final.', 5, 'India Davis Cup 2025 93 Year Wait', 'India Wins Davis Cup Final After 93-Year Wait', 'India Davis Cup final 2025 Australia Melbourne', 1, 'india-davis-cup-2025-93-year-wait', 'sports'),
(54, 'Yashasvi Jaiswal Scores Triple Century in Test Match Against England', '<p>Yashasvi Jaiswal became the youngest player in the history of Test cricket to score a triple century, making 312 not out against England at Wankhede Stadium in the first Test of India home series. The innings, spanning 448 balls and containing 34 fours and eight sixes, surpassed the previous mark for the fastest triple century by balls faced in Indian Test history. Jaiswal, 23, added 367 runs with Rohit Sharma for the second wicket to put India in a commanding position from which England never recovered, eventually losing by an innings and 178 runs. England Captain Ben Stokes admitted after the match that no team in world cricket has a batting lineup capable of challenging India in Indian conditions at this time. Jaiswal has now scored six double centuries in 22 Test innings, a frequency no player in history has achieved.</p>', 'Yashasvi Jaiswal, 23, scores an unbeaten 312 against England to become the youngest Test triple centurion in cricket history.', '06 October 2025', '2025-10-06 18:00:00', 'news-sports-014.webp', 'news-banner-sports-014.webp', 3, 3, 'On', 'Yashasvi Jaiswal Triple Century Test England 2025', 'Yashasvi Jaiswal 312, triple century Test cricket, India England Test 2025', 'Yashasvi Jaiswal scores 312 not out against England, becoming the youngest triple centurion in Test cricket history.', 5, 'Yashasvi Jaiswal Triple Century Test', 'Yashasvi Jaiswal Scores Triple Century in Test Match Against England', 'Yashasvi Jaiswal 312 triple century Test England 2025', 1, 'yashasvi-jaiswal-triple-century-test-england', 'sports'),
(55, 'India Women Football Team Qualifies for AFC Asian Cup for First Time', '<p>The India women national football team qualified for the AFC Women Asian Cup for the first time in 16 years, sealing their berth in the tournament after defeating Nepal 3-0 in the final qualifying match in Kathmandu. Dangmei Grace, the captain from Manipur, scored twice and set up the third goal for Anju Tamang in what the All India Football Federation described as a defining result in the modern era of the Indian women game. The squad has been transformed by a three-year collaboration between the AIFF and the German Football Association that overhauled coaching methods, physical conditioning, and data analytics applied to player selection. The qualification came amid a surge in grassroots women football participation catalysed by the FIFA Under-17 Women World Cup India hosted on home soil last year.</p>', 'India women football team qualifies for the AFC Asian Cup for the first time in 16 years after beating Nepal 3-0 in Kathmandu.', '15 October 2025', '2025-10-15 19:30:00', 'news-sports-015.webp', 'news-banner-sports-015.webp', 3, 3, 'On', 'India Women Football AFC Asian Cup Qualifier 2025', 'India women football, AFC Asian Cup 2025, Dangmei Grace, AIFF women', 'India women football team qualifies for AFC Asian Cup for first time in 16 years, beating Nepal 3-0.', 5, 'India Women Football AFC Asian Cup 2025', 'India Women Football Team Qualifies for AFC Asian Cup for First Time', 'India women football AFC Asian Cup qualifier 2025', 1, 'india-women-football-afc-asian-cup-qualifier', 'sports'),
(56, 'Carlos Alcaraz Wins Wimbledon for Third Consecutive Year', '<p>Carlos Alcaraz claimed his third consecutive Wimbledon title in London, defeating Novak Djokovic 7-5, 6-7, 6-3, 4-6, 7-5 in an epic five-set final that lasted over four hours and produced some of the finest grass-court tennis in the Open Era. Alcaraz, 22, became the youngest player to win Wimbledon three times, a feat that previously took Roger Federer until the age of 29. The match was finely balanced through four sets before Alcaraz broke in the 10th game of the fifth to seal the title. Djokovic, competing at his 24th Wimbledon, received a lengthy standing ovation as he left the court in what many commentators suggested may be his final Wimbledon final appearance. Alcaraz is the first player since Federer to win Wimbledon in three consecutive years and has now won six Grand Slam titles by the age of 22.</p>', 'Alcaraz wins a third consecutive Wimbledon title, defeating Djokovic in a five-set final for the ages at 22 years old.', '13 July 2025', '2025-07-13 18:30:00', 'news-sports-016.webp', 'news-banner-sports-016.webp', 3, 3, 'On', 'Alcaraz Wimbledon 2025 Third Consecutive Title', 'Alcaraz Wimbledon 2025, Djokovic final, Wimbledon three consecutive, tennis Grand Slam', 'Alcaraz wins his third consecutive Wimbledon, beating Djokovic 7-5 in the fifth set at 22 years old.', 5, 'Alcaraz Wimbledon Third Consecutive 2025', 'Carlos Alcaraz Wins Wimbledon for Third Consecutive Year', 'Alcaraz Wimbledon 2025 third consecutive Djokovic', 1, 'alcaraz-wimbledon-2025-third-consecutive', 'sports'),
(57, 'India Announce New National Cricket Stadium with 1.5 Lakh Capacity in Ahmedabad', '<p>The Board of Control for Cricket in India confirmed plans for a second major cricket stadium in Ahmedabad, to be built adjacent to the existing Narendra Modi Stadium, which will increase Ahmedabad total cricket seating capacity to over 1.5 lakh — making it the largest cricket-hosting city in the world by capacity. The new 80,000-seat stadium, to be constructed by the Gujarat Cricket Association with central government support, will feature a retractable roof, hybrid turf, and a complete underground parking facility for 8,000 vehicles. Construction is expected to begin in Q3 2025 with a completion target of December 2028. The new stadium will be the primary venue for the ICC World Test Championship finals in 2029 and 2031, which India has secured the hosting rights for.</p>', 'India announces a new 80,000-seat cricket stadium in Ahmedabad, taking total city capacity to 1.5 lakh — world largest.', '22 March 2025', '2025-03-22 10:00:00', 'news-sports-017.webp', 'news-banner-sports-017.webp', 3, 3, 'On', 'India New Cricket Stadium Ahmedabad 1.5 Lakh Capacity', 'Ahmedabad cricket stadium, new India cricket ground, BCCI stadium 2028, Gujarat cricket', 'BCCI announces new 80,000-seat Ahmedabad stadium, creating world largest cricket city with 1.5 lakh total capacity.', 5, 'India New Cricket Stadium Ahmedabad 2025', 'India Announce New National Cricket Stadium with 1.5 Lakh Capacity in Ahmedabad', 'India new cricket stadium Ahmedabad 1.5 lakh capacity 2025', 1, 'india-new-cricket-stadium-ahmedabad-1-5-lakh', 'sports'),
(58, 'International Olympic Committee Confirms Brisbane 2032 Opening Ceremony Venue', '<p>The International Olympic Committee confirmed the Gabba cricket ground in Brisbane as the primary venue for the opening and closing ceremonies of the 2032 Olympic Games, following a comprehensive upgrade that will transform it into a 50,000-seat multi-sport arena with a fully retractable roof. Queensland government officials confirmed construction work on the new Gabba will begin in Q1 2026 at a total cost of AUD 3.4 billion. The IOC also announced the first 15 sports on the Brisbane 2032 competition programme, with skateboarding, surfing, sport climbing, and breaking all confirmed to return from the Paris Games. India has requested the inclusion of kabaddi as an exhibition sport at Brisbane 2032 and received a formal indication from the IOC that the application is under active consideration.</p>', 'IOC confirms the Gabba as Brisbane 2032 Olympics ceremony venue, with India requesting kabaddi as an exhibition sport.', '18 February 2026', '2026-02-18 10:00:00', 'news-sports-018.webp', 'news-banner-sports-018.webp', 3, 3, 'On', 'Brisbane 2032 Olympics Gabba Venue IOC Confirm', 'Brisbane 2032 Olympics, Gabba venue, IOC 2032, kabaddi Olympics', 'IOC confirms the Gabba as the Brisbane 2032 Olympics ceremony venue, with India lobbying for kabaddi as an exhibition sport.', 5, 'Brisbane 2032 Olympics Gabba IOC Confirm', 'International Olympic Committee Confirms Brisbane 2032 Opening Ceremony Venue', 'Brisbane 2032 Olympics Gabba venue IOC India kabaddi', 1, 'brisbane-2032-olympics-gabba-venue-ioc-confirmed', 'sports'),
(59, 'Rohit Sharma Retires from All International Cricket', '<p>Rohit Sharma announced his retirement from all forms of international cricket at a press conference in Mumbai, bringing to a close a 17-year career in which he became one of the most prolific batters in the history of the sport. The 38-year-old leaves with 10,709 Test runs, 10,709 ODI runs, and 4,611 T20I runs — the only player in history to have crossed 10,000 runs in two formats. As captain, Rohit led India to the ICC T20 World Cup in 2024, the ICC Champions Trophy in 2025, and three consecutive Asia Cups. He departs as the highest scorer in T20 International cricket history and the holder of three individual ODI scores of 200 or more. The BCCI announced that the Wankhede Stadium opening stand will be named the Rohit Sharma End in his honour.</p>', 'Rohit Sharma retires from all international cricket at 38, having amassed 10,000+ runs in two formats and won two ICC trophies as captain.', '10 January 2026', '2026-01-10 12:00:00', 'news-sports-019.webp', 'news-banner-sports-019.webp', 3, 3, 'On', 'Rohit Sharma Retirement All Cricket 2026', 'Rohit Sharma retirement, India cricket retirement 2026, Rohit career stats', 'Rohit Sharma retires from international cricket after 17 years with 10,000-plus runs in two formats and two ICC titles.', 5, 'Rohit Sharma Retirement International Cricket', 'Rohit Sharma Retires from All International Cricket', 'Rohit Sharma retirement all formats international cricket 2026', 1, 'rohit-sharma-retires-all-international-cricket-2026', 'sports');
INSERT INTO `tbl_news` (`news_id`, `news_title`, `news_content`, `news_content_short`, `news_date`, `published_at`, `photo`, `banner`, `category_id`, `author_id`, `comment`, `meta_title`, `meta_keyword`, `meta_description`, `lang_id`, `stitle`, `title`, `img_alt`, `domain_id`, `encode_title`, `type`) VALUES
(60, 'India Para Athletes Win Record 29 Medals at Paris 2024 Paralympics', '<p>India para athletes concluded the Paris 2024 Paralympic Games with a record 29 medals — seven gold, nine silver, and thirteen bronze — finishing 18th on the overall medal tally, the highest-ever finish for a Paralympic India contingent. Avani Lekhara retained her gold in the 10m air rifle and became India most decorated Paralympic athlete with a total of four medals across two Games. Sumit Antil defended his javelin gold with a world record throw of 70.59 metres that was met with a standing ovation at the Stade de France. India Department of Empowerment of Persons with Disabilities announced a total cash award of Rs 45 crore for the contingent. Paralympic Committee of India credited the result to the Khelo India Para Games and a target-based training programme that tracked each athlete across 120 measurable performance parameters.</p>', 'India wins a record 29 Paralympic medals at Paris 2024, finishing 18th globally as Lekhara and Antil defend gold medals.', '08 September 2024', '2024-09-08 20:00:00', 'news-sports-020.webp', 'news-banner-sports-020.webp', 3, 3, 'On', 'India Paralympics Paris 2024 Record 29 Medals', 'India Paralympics 2024, Avani Lekhara, Sumit Antil, Paris Paralympic India', 'India wins a record 29 medals at Paris 2024 Paralympics with Lekhara and Antil defending gold as world record holders.', 5, 'India Paralympics Paris 2024 Record Medals', 'India Para Athletes Win Record 29 Medals at Paris 2024 Paralympics', 'India Paralympics Paris 2024 29 medals record', 1, 'india-paralympics-paris-2024-record-29-medals', 'sports'),
(61, 'WHO Declares Global Health Emergency Over Novel Avian Influenza H5N9 Strain', '<p>The World Health Organisation declared a Public Health Emergency of International Concern after a novel avian influenza strain designated H5N9 was confirmed in 31 countries, with sustained human-to-human transmission detected in clusters across Vietnam, Indonesia, and Nigeria. The H5N9 strain has a recorded case fatality rate of 22% among hospitalised patients, significantly higher than seasonal influenza. India National Centre for Disease Control activated its Integrated Disease Surveillance Programme emergency protocols and confirmed no domestic cases as of the declaration date, while quarantine screening was enhanced at all 32 international airports. WHO Director-General declared that the window for containment is narrow and urged wealthy nations to immediately share vaccine manufacturing capacities with low-income countries. India Serum Institute of India confirmed it can produce 500 million doses of H5N9 vaccine candidate within eight months of receiving an approved seed strain.</p>', 'WHO declares H5N9 avian influenza a global health emergency with 22% fatality rate in 31 countries and human transmission confirmed.', '14 March 2025', '2025-03-14 12:00:00', 'news-health-001.webp', 'news-banner-health-001.webp', 4, 4, 'On', 'WHO H5N9 Avian Influenza Global Emergency 2025', 'H5N9 avian flu, WHO emergency, bird flu 2025, India health alert', 'WHO declares H5N9 avian influenza a global emergency with 22% case fatality and human transmission in 31 countries.', 5, 'WHO H5N9 Avian Influenza Emergency 2025', 'WHO Declares Global Health Emergency Over Novel Avian Influenza H5N9 Strain', 'WHO H5N9 avian influenza global emergency 2025', 1, 'who-h5n9-avian-influenza-global-health-emergency', 'health'),
(62, 'India Achieves Zero Polio for 15 Consecutive Years, WHO Certifies Milestone', '<p>The World Health Organisation formally certified India polio-free status for the 15th consecutive year, acknowledging the country sustained interruption of wild poliovirus transmission since January 13, 2011. The achievement is extraordinary for a country that once accounted for nearly half the world polio cases and was considered the most difficult context in which to achieve elimination due to population density, sanitation challenges, and complex vaccine hesitancy patterns. The Pulse Polio immunisation programme, which administers oral vaccines to every child under five in a single national day, reached 172 million children in 2025 across 32 million immunisation booths. The Union Health Ministry attributed the sustained success to geospatial tracking of zero-dose children, rapid response surveillance, and a dedicated cadre of 2.3 million frontline vaccination workers.</p>', 'WHO certifies India 15 consecutive years of polio-free status, recognising a programme reaching 172 million children annually.', '13 January 2026', '2026-01-13 10:00:00', 'news-health-002.webp', 'news-banner-health-002.webp', 4, 4, 'On', 'India Polio Free 15 Years WHO Certification 2026', 'India polio free, WHO India certificate, Pulse Polio, polio elimination India', 'WHO certifies India 15 consecutive years of polio-free status reached through Pulse Polio and surveillance programmes.', 5, 'India Polio Free 15 Years WHO 2026', 'India Achieves Zero Polio for 15 Consecutive Years, WHO Certifies Milestone', 'India polio free 15 years WHO certification 2026', 1, 'india-polio-free-15-years-who-certification', 'health'),
(63, 'Scientists Achieve First Complete Reversal of Type 2 Diabetes Through Gene Therapy', '<p>A landmark clinical trial conducted at Massachusetts General Hospital and Stanford University Medical Centre demonstrated the first complete and durable reversal of Type 2 diabetes in adult patients through a single-dose gene therapy that reprogrammed pancreatic cells to restore insulin secretion. The trial enrolled 60 patients who had lived with Type 2 diabetes for an average of 14 years, all of whom discontinued all diabetes medication within six months of receiving the treatment. At the 18-month follow-up, 54 of 60 participants maintained normal blood glucose regulation with no pharmacological intervention. The therapy uses an adeno-associated virus vector to deliver a modified PDX1 transcription factor to pancreatic beta-cell precursors. India has an estimated 101 million people living with Type 2 diabetes — the highest burden of any country globally — and the Indian Council of Medical Research has initiated discussions to join Phase 3 expansion trials.</p>', 'Scientists achieve first complete gene therapy reversal of Type 2 diabetes in 54 of 60 patients, ending their need for medication.', '20 April 2025', '2025-04-20 14:00:00', 'news-health-003.webp', 'news-banner-health-003.webp', 4, 4, 'On', 'Type 2 Diabetes Gene Therapy Reversal 2025', 'Type 2 diabetes cure, gene therapy diabetes, diabetes reversal India, insulin gene therapy', 'Scientists achieve first complete gene therapy reversal of Type 2 diabetes with 54 of 60 patients off all medication.', 5, 'Type 2 Diabetes Gene Therapy Cure 2025', 'Scientists Achieve First Complete Reversal of Type 2 Diabetes Through Gene Therapy', 'Type 2 diabetes gene therapy reversal cure 2025', 1, 'type-2-diabetes-gene-therapy-reversal-2025', 'health'),
(64, 'India Approves Universal Cervical Cancer Vaccination for All Girls Aged 9-14', '<p>The Union Cabinet approved the introduction of a free national cervical cancer vaccination programme covering all girls aged nine to fourteen across India, making it one of the largest public vaccination rollouts since the COVID-19 programme. The Cervavac vaccine, manufactured domestically by the Serum Institute of India at a cost of Rs 200 per dose, will be administered as a two-dose schedule through schools and anganwadis over a three-year rollout beginning in April 2025. India records approximately 127,000 new cervical cancer cases annually, accounting for roughly one-quarter of global cervical cancer incidence, making it a major public health burden. WHO Regional Director for South-East Asia praised the decision, estimating the programme will prevent 80,000 cancer deaths per year by 2040. States will receive performance-linked health grants to drive coverage above 90% of the eligible population.</p>', 'India launches free cervical cancer vaccination for all girls aged 9-14 using domestic Cervavac at Rs 200 per dose.', '25 March 2025', '2025-03-25 10:00:00', 'news-health-004.webp', 'news-banner-health-004.webp', 4, 4, 'On', 'India Cervical Cancer Vaccine Girls 9-14 Free 2025', 'cervical cancer vaccine India, Cervavac India, HPV vaccine India, free vaccine girls', 'India launches universal free cervical cancer vaccination for girls aged 9-14 using domestically made Cervavac.', 5, 'India Cervical Cancer Vaccine Girls 2025', 'India Approves Universal Cervical Cancer Vaccination for All Girls Aged 9-14', 'India cervical cancer vaccine girls 9-14 free Cervavac 2025', 1, 'india-cervical-cancer-vaccine-girls-9-14-2025', 'health'),
(65, 'AI Model Detects Early Pancreatic Cancer with 92% Accuracy from CT Scans', '<p>Researchers at Johns Hopkins University and the UK National Health Service published results of a clinical validation study showing their AI model Prism achieved 92% sensitivity in detecting stage one and two pancreatic cancer from routine abdominal CT scans — a disease that typically presents no symptoms until stage three or four when survival rates are below 15%. The model was trained on 24,000 annotated CT scans and validated on a separate dataset of 9,000 scans from 18 hospitals across five countries. Prism reduces radiologist reading time per scan by 60% and identifies micro-lesions as small as four millimetres that human radiologists routinely miss. Apollo Hospitals and Fortis Healthcare in India have signed agreements to integrate Prism into their radiology workflows starting in 2026. WHO estimates that early detection at stage one through tools like Prism could raise five-year pancreatic cancer survival from 11% to over 55%.</p>', 'AI model Prism detects early pancreatic cancer with 92% accuracy from CT scans, potentially raising survival from 11% to 55%.', '10 June 2025', '2025-06-10 14:00:00', 'news-health-005.webp', 'news-banner-health-005.webp', 4, 4, 'On', 'AI Pancreatic Cancer Detection 92 Percent CT Scan 2025', 'pancreatic cancer AI detection, Prism AI radiology, early cancer detection AI, Apollo AI cancer', 'AI model Prism detects early pancreatic cancer with 92% accuracy, with Apollo and Fortis integrating it in India.', 5, 'AI Pancreatic Cancer Detection Prism', 'AI Model Detects Early Pancreatic Cancer with 92% Accuracy from CT Scans', 'AI pancreatic cancer detection 92 percent CT scan 2025', 1, 'ai-pancreatic-cancer-detection-92-percent-ct-scan', 'health'),
(66, 'India Reports Sharp Rise in Non-Communicable Diseases Driven by Urban Lifestyle', '<p>A nationwide study conducted by the Indian Council of Medical Research across 24 states confirmed that non-communicable diseases — including type 2 diabetes, hypertension, cardiovascular disease, and chronic respiratory disease — now account for 67% of all deaths in India, up from 53% a decade ago. Urban areas showed a significantly higher NCD burden than rural areas, with three times the prevalence of hypertension and double the rate of metabolic syndrome. Sedentary work culture, ultra-processed food consumption, and chronic sleep deprivation were identified as the three primary drivers. The National Programme for Prevention and Control of NCDs, launched in 2013, has been substantially restructured with an added focus on workplace wellness mandates for companies employing more than 500 people. The ICMR report recommends making blood pressure and blood glucose screening free and mandatory at every outpatient visit in government hospitals.</p>', 'ICMR study finds NCDs now cause 67% of India deaths, with urban sedentary lifestyles driving sharp rises in diabetes and heart disease.', '30 July 2025', '2025-07-30 10:00:00', 'news-health-006.webp', 'news-banner-health-006.webp', 4, 4, 'On', 'India NCD Rise Urban Lifestyle ICMR Study 2025', 'NCD India 2025, non-communicable disease India, India diabetes hypertension rise', 'ICMR confirms NCDs cause 67% of India deaths driven by urban sedentary lifestyles and ultra-processed food.', 5, 'India NCD Rise Urban Lifestyle 2025', 'India Reports Sharp Rise in Non-Communicable Diseases Driven by Urban Lifestyle', 'India NCD rise urban lifestyle ICMR 2025', 1, 'india-ncd-rise-urban-lifestyle-icmr-2025', 'health'),
(67, 'Global Study Confirms Mediterranean Diet Reduces Dementia Risk by 23%', '<p>A 12-year longitudinal study involving 92,000 adults across 21 countries, published in The Lancet, confirmed that strict adherence to a Mediterranean diet — characterised by olive oil, legumes, whole grains, fish, vegetables, and low red meat consumption — reduces the risk of developing dementia by 23% compared to Western dietary patterns. The effect was largest in individuals who adopted the diet before age 50 and was independent of physical activity, education level, and genetic predisposition for Alzheimer disease. Neurologists at AIIMS Delhi and NIMHANS Bengaluru led the Indian arm of the study involving 8,000 participants. The findings are prompting India dietary guidelines committee to incorporate Mediterranean-style principles into the updated Indian diet recommendations due to be published in 2026, adapted for locally available ingredients such as dal, mustard oil, and seasonal vegetables.</p>', 'A 12-year global study confirms a Mediterranean diet reduces dementia risk by 23%, with Indian researchers contributing findings.', '14 August 2025', '2025-08-14 14:00:00', 'news-health-007.webp', 'news-banner-health-007.webp', 4, 4, 'On', 'Mediterranean Diet Dementia Risk 23 Percent Study 2025', 'Mediterranean diet dementia, diet brain health, Alzheimer prevention diet, India diet guidelines', 'Global study confirms Mediterranean diet cuts dementia risk by 23%, prompting India to update national dietary guidelines.', 5, 'Mediterranean Diet Dementia Risk Study 2025', 'Global Study Confirms Mediterranean Diet Reduces Dementia Risk by 23%', 'Mediterranean diet dementia risk 23 percent global study 2025', 1, 'mediterranean-diet-dementia-risk-23-percent-2025', 'health'),
(68, 'India Launches National Programme to Provide Free Mental Health Counselling in Schools', '<p>The Ministry of Education and Ministry of Health jointly launched the Manodarpan Plus programme, placing trained school counsellors in every government secondary school across India over a four-year rollout, covering approximately 165,000 schools and 85 million students. Each counsellor will be supported by an AI-assisted screening tool that flags at-risk students based on attendance, academic performance, and periodic wellness surveys without disclosing individual data to teachers or administrators. The programme also introduces a structured peer support framework called Saathi Mitra, training senior students as first-responders to mental health concerns among their peers. Pilot data from 1,200 schools showed a 38% reduction in dropout rates and a 29% reduction in bullying incidents among schools with active counselling programmes. UNICEF and the World Health Organisation co-funded the programme architecture design.</p>', 'India places counsellors in all 165,000 government secondary schools through Manodarpan Plus, covering 85 million students.', '15 September 2025', '2025-09-15 09:00:00', 'news-health-008.webp', 'news-banner-health-008.webp', 4, 4, 'On', 'India School Mental Health Manodarpan Plus 2025', 'Manodarpan school counsellor, mental health schools India, school counselling India', 'India places trained counsellors in all 165,000 government secondary schools through Manodarpan Plus programme.', 5, 'India School Mental Health Manodarpan 2025', 'India Launches National Programme to Provide Free Mental Health Counselling in Schools', 'India school mental health counselling Manodarpan 2025', 1, 'india-school-mental-health-manodarpan-plus', 'health'),
(69, 'New Drug Ozempic Successor Tirzepatide Shows 22% Body Weight Reduction', '<p>Results from the Phase 4 real-world evidence study of tirzepatide — sold as Mounjaro by Eli Lilly — demonstrated an average body weight reduction of 22.5% over 72 weeks in obese patients without type 2 diabetes, confirming even stronger effectiveness in clinical practice than in the original trial. The drug, which acts on both GLP-1 and GIP receptors, produced clinically significant improvements in blood pressure, triglycerides, and sleep apnoea severity. Tirzepatide supply constraints that plagued 2024 have been largely resolved following Eli Lilly expanded manufacturing investment, and the drug has received price approvals from insurance regulators in 14 additional countries. India Drug Controller General approved tirzepatide for obesity treatment in adults with a BMI above 30, with reimbursement under consideration for Ayushman Bharat for patients with comorbid diabetes.</p>', 'Tirzepatide achieves 22.5% body weight reduction in real-world Phase 4 data, with India approval for obesity treatment secured.', '28 October 2025', '2025-10-28 14:00:00', 'news-health-009.webp', 'news-banner-health-009.webp', 4, 4, 'On', 'Tirzepatide Weight Loss 22 Percent India Approval 2025', 'tirzepatide, Mounjaro obesity India, GLP-1 GIP weight loss, DCGI tirzepatide', 'Tirzepatide achieves 22.5% body weight reduction in real-world study; India approves it for obesity treatment.', 5, 'Tirzepatide 22 Percent Weight Loss India', 'New Drug Ozempic Successor Tirzepatide Shows 22% Body Weight Reduction', 'tirzepatide 22 percent weight loss obesity India approval 2025', 1, 'tirzepatide-22-percent-weight-loss-obesity-india', 'health'),
(70, 'India Reports Dramatic Fall in Infant Mortality to 19 per 1000 Live Births', '<p>India Sample Registration System bulletin confirmed that the country infant mortality rate has fallen to 19 per 1,000 live births for the first time, down from 32 per 1,000 in 2015 — a 40% improvement in a decade that public health experts describe as exceptional for a country of India scale. The decline was steepest in Madhya Pradesh, Uttar Pradesh, and Odisha — historically the highest-burden states — which have each reduced infant mortality by over 50% in the same period. Improved institutional delivery rates, now at 91%, expansion of neonatal care units at district hospitals, and the government-funded Janani Suraksha Yojana conditional cash transfer for hospital deliveries were credited as the primary drivers. UNICEF India Representative commended the results and noted India is now tracking ahead of schedule to reach Sustainable Development Goal targets for child mortality by 2030.</p>', 'India infant mortality rate falls to 19 per 1,000 live births, a 40% improvement in a decade driven by institutional deliveries.', '18 November 2025', '2025-11-18 10:00:00', 'news-health-010.webp', 'news-banner-health-010.webp', 4, 4, 'On', 'India Infant Mortality Rate 19 SRS 2025', 'India infant mortality, IMR India 2025, maternal health India, neonatal care', 'India infant mortality rate falls to 19 per 1,000 live births, a 40% decade improvement driven by institutional deliveries.', 5, 'India Infant Mortality 19 Per 1000 2025', 'India Reports Dramatic Fall in Infant Mortality to 19 per 1000 Live Births', 'India infant mortality 19 per 1000 SRS 2025', 1, 'india-infant-mortality-19-per-1000-live-births', 'health'),
(71, 'Global Antibiotic Pipeline Shows 12 New Candidates Targeting Drug-Resistant Bacteria', '<p>The WHO global pipeline report on new antibiotics confirmed 12 new clinical-stage drug candidates targeting priority drug-resistant bacteria including carbapenem-resistant Enterobacteriaceae, methicillin-resistant Staphylococcus aureus, and multidrug-resistant tuberculosis. Three of the 12 candidates are being developed by Indian pharmaceutical companies — Dr Reddy Laboratories, Lupin, and Wockhardt — representing a significant step in India contribution to global antimicrobial resistance solutions. Two of the Indian-developed compounds use novel mechanism of action classes not previously represented in clinical antibiotic development. WHO said the pipeline remains critically underfunded compared to the scale of the AMR crisis but noted the Indian entries as a bright spot for innovation in a field traditionally ignored by pharmaceutical investment. The ICMR has committed Rs 800 crore over five years to support pre-clinical and Phase 1 antibiotic research in India.</p>', 'WHO antibiotic pipeline report shows 12 new candidates, with three from Indian pharma companies using novel mechanisms.', '22 December 2025', '2025-12-22 10:00:00', 'news-health-011.webp', 'news-banner-health-011.webp', 4, 4, 'On', 'WHO Antibiotic Pipeline India Pharma 2025', 'antibiotic pipeline WHO, drug resistant bacteria India, AMR antibiotic India, Lupin Dr Reddy antibiotic', 'WHO confirms 12 new antibiotic candidates with three from Indian pharma companies targeting drug-resistant bacteria.', 5, 'WHO Antibiotic Pipeline Indian Pharma 2025', 'Global Antibiotic Pipeline Shows 12 New Candidates Targeting Drug-Resistant Bacteria', 'WHO antibiotic pipeline India pharma 12 candidates 2025', 1, 'global-antibiotic-pipeline-12-candidates-india', 'health'),
(72, 'India Gains Access to Gilead Hepatitis C Cure for Rs 300 Per Course', '<p>The Indian government concluded a voluntary licensing agreement with Gilead Sciences securing the right to manufacture and distribute pan-genotypic direct-acting antiviral hepatitis C treatment at a cost of Rs 300 per complete 12-week treatment course — a fraction of the Rs 75,000 commercial price. Three Indian generic manufacturers including Natco Pharma, Cipla, and Mylan India will begin manufacturing under the licence from July 2025. India has an estimated 7.5 million people living with chronic hepatitis C infection, the majority in rural areas who cannot afford commercial pricing. The National Viral Hepatitis Control Programme will integrate the generic treatment into its free medicine supply across all government health facilities. WHO has cited the deal as a model for how middle-income countries can negotiate access to curative medicines without compromising manufacturer intellectual property internationally.</p>', 'India secures hepatitis C treatment for Rs 300 per course through a Gilead voluntary licence, reaching 7.5 million patients.', '15 June 2025', '2025-06-15 10:00:00', 'news-health-012.webp', 'news-banner-health-012.webp', 4, 4, 'On', 'India Hepatitis C Treatment Rs 300 Gilead Generic 2025', 'hepatitis C India affordable, Gilead India licence, hepatitis cure India, Natco Cipla hepatitis', 'India secures Rs 300 hepatitis C cure through Gilead licence, enabling treatment for 7.5 million patients via government health facilities.', 5, 'India Hepatitis C Rs 300 Gilead 2025', 'India Gains Access to Gilead Hepatitis C Cure for Rs 300 Per Course', 'India hepatitis C treatment Rs 300 Gilead generic 2025', 1, 'india-hepatitis-c-cure-rs-300-gilead-licence', 'health'),
(73, 'China Reports Successful Human Trial of Lab-Grown Lung Tissue Transplant', '<p>Scientists at the Tongji Medical College in Wuhan, China published results confirming the world first successful transplantation of bioengineered lung tissue grown from a patient own stem cells into a human recipient, with six-month follow-up data showing 78% lung function recovery compared to 42% for conventional donor lung transplants. The lung scaffold was created by seeding a decellularised donor lung matrix with induced pluripotent stem cells derived from the recipient blood sample, eliminating the risk of immune rejection that requires lifelong immunosuppressive drugs in conventional transplants. China National Health Commission has approved a 50-patient expanded trial at three centres. India National Organ and Tissue Transplant Organisation has initiated a memorandum of understanding with Tongji Medical College to observe and participate in the next trial phase.</p>', 'China reports the world first successful bioengineered lab-grown lung tissue transplant with 78% function recovery at six months.', '25 August 2025', '2025-08-25 09:00:00', 'news-health-013.webp', 'news-banner-health-013.webp', 4, 4, 'On', 'China Lab Grown Lung Transplant Success 2025', 'lab grown lung China, bioengineered organ transplant, stem cell lung, organ regeneration 2025', 'China reports world first lab-grown lung tissue transplant success with 78% function recovery at six months.', 5, 'China Lab Grown Lung Transplant 2025', 'China Reports Successful Human Trial of Lab-Grown Lung Tissue Transplant', 'China lab grown lung transplant success human trial 2025', 1, 'china-lab-grown-lung-transplant-human-trial-2025', 'health'),
(74, 'India Rolls Out Nationwide Sickle Cell Disease Screening for Tribal Communities', '<p>The Ministry of Tribal Affairs and Ministry of Health jointly launched the National Sickle Cell Anaemia Elimination Mission, targeting the screening of 70 million individuals from tribal communities across 17 states where sickle cell disease prevalence is highest. Mobile screening camps equipped with point-of-care HPLC testing devices will visit every tribal village in the targeted states over three years. Individuals identified as carriers will receive genetic counselling, and those diagnosed with sickle cell disease will be enrolled in the Ayushman Bharat scheme with specialised care pathways including hydroxyurea therapy and regular blood transfusion access. The mission has partnered with CRISPR gene therapy researchers at Christian Medical College Vellore to create a referral pathway for severe cases to the ongoing clinical trial. PM Modi addressed tribal communities at the launch, calling sickle cell elimination a matter of social justice.</p>', 'India launches the Sickle Cell Elimination Mission screening 70 million tribal individuals across 17 states with point-of-care testing.', '10 July 2025', '2025-07-10 10:00:00', 'news-health-014.webp', 'news-banner-health-014.webp', 4, 4, 'On', 'India Sickle Cell Mission Tribal Screening 2025', 'sickle cell India, tribal health India, sickle cell elimination mission, HPLC tribal screening', 'India launches Sickle Cell Elimination Mission screening 70 million tribal individuals across 17 states.', 5, 'India Sickle Cell Elimination Mission 2025', 'India Rolls Out Nationwide Sickle Cell Disease Screening for Tribal Communities', 'India sickle cell mission tribal screening 70 million 2025', 1, 'india-sickle-cell-elimination-mission-tribal', 'health'),
(75, 'UK Approves First AI-Designed Drug to Enter Human Clinical Trials', '<p>The UK Medicines and Healthcare products Regulatory Agency approved the first drug molecule designed entirely by artificial intelligence — developed by Insilico Medicine using its generative chemistry platform — to enter Phase 2 human clinical trials for idiopathic pulmonary fibrosis. The molecule, designated INS018_055, was designed, synthesised, and optimised entirely by AI without human chemists selecting the molecular structure. Phase 1 safety data from 80 volunteers showed no significant adverse events and confirmed the molecule reaches target tissue at therapeutic concentrations. The approval is considered a watershed in drug discovery, demonstrating that AI can identify new chemical entities faster than any human-driven research programme. India Sun Pharmaceutical Industries has licensed co-development rights for INS018_055 for Asian markets and will co-fund the Phase 2 trials expected to begin in Q3 2025.</p>', 'UK approves the first entirely AI-designed drug molecule to enter Phase 2 human trials, with Sun Pharma licensed for Asian markets.', '18 April 2025', '2025-04-18 14:00:00', 'news-health-015.webp', 'news-banner-health-015.webp', 4, 4, 'On', 'AI Designed Drug Human Trial UK Insilico 2025', 'AI drug discovery, Insilico Medicine, AI drug Phase 2, Sun Pharma AI drug', 'UK approves first entirely AI-designed drug for Phase 2 trials in IPF; Sun Pharma licensed for Asian markets.', 5, 'AI Designed Drug UK Phase 2 Trial 2025', 'UK Approves First AI-Designed Drug to Enter Human Clinical Trials', 'UK AI designed drug human clinical trial Insilico 2025', 1, 'uk-ai-designed-drug-human-clinical-trials-2025', 'health'),
(76, 'India Achieves 100% Institutional Delivery Rate in Five States', '<p>Health mission data from the Ministry of Health and Family Welfare confirmed that five Indian states — Kerala, Goa, Tamil Nadu, Telangana, and Himachal Pradesh — have achieved 100% institutional delivery rates, meaning every recorded birth in those states in the 2024-25 fiscal year occurred in a health facility rather than at home. The milestone reflects decades of investment in primary health centre infrastructure, the Pradhan Mantri Matru Vandana Yojana maternity benefit scheme, and targeted interventions under the National Rural Health Mission. National institutional delivery rate stands at 91.2%, the highest ever recorded and up from 52% in 2005. Maternal mortality in the five top-performing states averages 25 per 100,000 live births, approaching European-level outcomes. The government has announced fast-tracking of a comprehensive maternity entitlement package for all women that includes 26 weeks of paid leave.</p>', 'Five Indian states achieve 100% institutional delivery rates as India national rate hits a record 91.2%, cutting maternal mortality.', '25 February 2026', '2026-02-25 10:00:00', 'news-health-016.webp', 'news-banner-health-016.webp', 4, 4, 'On', 'India Institutional Delivery 100 Percent Five States 2026', 'institutional delivery India, maternal health India, Kerala Goa Tamil Nadu delivery', 'Five Indian states reach 100% institutional delivery as national rate hits a record 91.2%, cutting maternal mortality.', 5, 'India Institutional Delivery 100 Percent States', 'India Achieves 100% Institutional Delivery Rate in Five States', 'India 100 percent institutional delivery five states 2026', 1, 'india-100-percent-institutional-delivery-five-states', 'health'),
(77, 'Harvard Study Finds Daily Yoga Reduces Cortisol Levels by 30% in Stressed Adults', '<p>A 12-week randomised controlled trial conducted by Harvard T.H. Chan School of Public Health in collaboration with India National Institute of Mental Health and Neurosciences confirmed that adults who practised Hatha yoga for 45 minutes daily experienced a 30% reduction in salivary cortisol levels — the primary biological marker of chronic stress — compared to an active control group performing equivalent-intensity aerobic exercise. Participants in the yoga group also showed significantly improved heart rate variability, a 22% reduction in self-reported anxiety scores, and improved sleep quality as measured by polysomnography. The study enrolled 850 adults with clinically elevated occupational stress in Bengaluru, Boston, and London. WHO has cited the findings in an updated evidence review on mind-body practices for stress-related disorders. India Ministry of AYUSH is funding a larger 5,000-participant replication study across 10 countries.</p>', 'Harvard and NIMHANS confirm daily Hatha yoga reduces cortisol by 30% and anxiety by 22% in a rigorous 850-person trial.', '05 March 2026', '2026-03-05 14:00:00', 'news-health-017.webp', 'news-banner-health-017.webp', 4, 4, 'On', 'Harvard Yoga Cortisol Stress Study 2026', 'yoga stress cortisol study, Harvard yoga, NIMHANS yoga research, yoga mental health evidence', 'Harvard and NIMHANS study confirms daily yoga reduces cortisol by 30% and anxiety by 22% in stressed adults.', 5, 'Harvard Yoga Cortisol Study 2026', 'Harvard Study Finds Daily Yoga Reduces Cortisol Levels by 30% in Stressed Adults', 'Harvard NIMHANS yoga cortisol stress reduction study 2026', 1, 'harvard-yoga-cortisol-30-percent-stress-reduction', 'health'),
(78, 'US FDA Approves First Blood Test to Diagnose Alzheimer Disease', '<p>The United States Food and Drug Administration granted full approval to Lumipulse, a blood-based biomarker test developed by Fujirebio that can accurately diagnose Alzheimer disease by detecting abnormal ratios of amyloid-beta 40 and 42 proteins in blood plasma, replacing the need for expensive PET brain scans or invasive cerebrospinal fluid collection in most cases. Clinical validation studies showed 91% concordance with PET imaging results across a diverse dataset of 1,200 patients. The test costs approximately $200 compared to $5,000 for PET scans, dramatically expanding access to early diagnosis especially in low-resource settings. India Drug Controller General is reviewing an application for Lumipulse approval, with Apollo Diagnostics and SRL Diagnostics already planning nationwide rollout subject to regulatory clearance. Neurologists estimate early diagnosis enabled by Lumipulse could allow interventions that delay dementia onset by up to seven years.</p>', 'US FDA approves Lumipulse, a $200 blood test for Alzheimer diagnosis, replacing $5,000 PET scans in most cases.', '12 January 2026', '2026-01-12 18:00:00', 'news-health-018.webp', 'news-banner-health-018.webp', 4, 4, 'On', 'FDA Alzheimer Blood Test Lumipulse Approval 2026', 'Alzheimer blood test, Lumipulse FDA, early Alzheimer diagnosis, amyloid blood test', 'FDA approves Lumipulse Alzheimer blood test at $200, replacing $5,000 PET scans; India review underway.', 5, 'FDA Alzheimer Blood Test Lumipulse 2026', 'US FDA Approves First Blood Test to Diagnose Alzheimer Disease', 'FDA Alzheimer blood test Lumipulse approval 2026', 1, 'fda-alzheimer-blood-test-lumipulse-approval-2026', 'health'),
(79, 'India Extends Free Cancer Treatment to All Stages Under Ayushman Bharat', '<p>The Union Health Ministry expanded the Ayushman Bharat PM-JAY scheme to provide free cancer treatment including surgery, chemotherapy, radiation, and targeted therapy for all four stages of cancer, removing the previous Rs 5 lakh annual cap for oncology treatment. The expansion covers all cancers at government empanelled hospitals and 450 designated private cancer centres and is funded through a dedicated cancer pool created by the Finance Ministry. India records approximately 1.4 million new cancer cases annually, of which over 70% are diagnosed at stage three or four when treatment costs are highest. The expansion will benefit an estimated 600 million Ayushman Bharat beneficiaries who previously faced catastrophic out-of-pocket expenditure for cancer treatment. State cancer registries have been mandated to digitise all patient data and link it to a National Cancer Intelligence Platform for population-level planning.</p>', 'India expands Ayushman Bharat to cover all cancer stages with no cost cap, benefiting 600 million people across all treatment types.', '20 March 2026', '2026-03-20 09:00:00', 'news-health-019.webp', 'news-banner-health-019.webp', 4, 4, 'On', 'India Cancer Treatment Free Ayushman Bharat All Stages 2026', 'Ayushman Bharat cancer, free cancer treatment India, PM-JAY oncology, India cancer insurance', 'India expands Ayushman Bharat to cover all cancer stages with no treatment cap for 600 million beneficiaries.', 5, 'India Cancer Free Treatment Ayushman 2026', 'India Extends Free Cancer Treatment to All Stages Under Ayushman Bharat', 'India free cancer treatment Ayushman Bharat all stages 2026', 1, 'india-free-cancer-treatment-ayushman-bharat-all-stages', 'health'),
(80, 'Scientists Map Complete Human Epigenome, Opening New Era of Personalised Medicine', '<p>An international consortium of over 500 scientists from 25 countries published the first complete reference map of the human epigenome — the system of chemical modifications that control how genes are expressed without changing the underlying DNA sequence — in a landmark series of papers in Nature. The Human Epigenome Project mapped over four billion epigenetic marks across 33 distinct human cell types, creating a reference atlas that scientists can use to understand why the same gene behaves differently in brain cells versus liver cells versus immune cells. The discovery opens the possibility of epigenetic medicines that switch on or off specific genes involved in cancer, ageing, autoimmune disease, and psychiatric disorders without permanently altering the genome. India participated through six institutions including IISc, IGIB, and NCBS. Pharmaceutical companies worldwide are already investing in epigenetic drug discovery programmes based on the new atlas, with the first clinical candidates expected by 2028.</p>', 'Scientists complete the first full human epigenome map across 33 cell types, opening a new era of epigenetic medicine and gene control.', '28 March 2026', '2026-03-28 14:00:00', 'news-health-020.webp', 'news-banner-health-020.webp', 4, 4, 'On', 'Human Epigenome Map Complete Scientists 2026', 'human epigenome project, epigenetic medicine, gene expression map, epigenome atlas', 'Scientists publish the complete human epigenome map across 33 cell types, enabling a new era of personalised epigenetic medicine.', 5, 'Human Epigenome Map Complete 2026', 'Scientists Map Complete Human Epigenome, Opening New Era of Personalised Medicine', 'human epigenome complete map scientists 2026', 1, 'human-epigenome-complete-map-personalised-medicine', 'health');

